PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE user (
	id INTEGER NOT NULL, 
	username VARCHAR(150), 
	first_name VARCHAR(100) NOT NULL, 
	last_name VARCHAR(100) NOT NULL, 
	email VARCHAR(150) NOT NULL, 
	password_hash VARCHAR(150), 
	is_admin BOOLEAN, 
	bio TEXT, 
	profile_picture VARCHAR(200), reset_token VARCHAR(100), reset_token_expiry DATETIME, pronouns VARCHAR(100), date_of_birth DATE, location VARCHAR(200), email_verified BOOLEAN DEFAULT 0, verification_token VARCHAR(100), verification_token_expiry DATETIME, pending_email VARCHAR(150), email_change_token VARCHAR(100), email_change_token_expiry DATETIME, can_retake_assessment BOOLEAN DEFAULT 0, has_paid BOOLEAN DEFAULT 0, payment_waived_at DATETIME, profile_incomplete BOOLEAN DEFAULT 0, profile_completion_token VARCHAR(100), profile_completion_token_expiry DATETIME, disclaimer_agreed BOOLEAN DEFAULT 0, disclaimer_agreed_at DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (username), 
	UNIQUE (email)
);
CREATE TABLE assessment (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	answers TEXT, 
	reviewed BOOLEAN, 
	matched_user_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES user (id), 
	FOREIGN KEY(matched_user_id) REFERENCES user (id)
);
CREATE TABLE reviewer_assessment (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	pronouns VARCHAR(100), 
	age_range VARCHAR(50), 
	location VARCHAR(200), 
	answers TEXT, 
	created_at DATETIME, 
	reviewed BOOLEAN, 
	admin_notes TEXT, 
	PRIMARY KEY (id)
);
CREATE TABLE match (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        user1_id INTEGER NOT NULL,
                        user2_id INTEGER NOT NULL,
                        assessment1_id INTEGER NOT NULL,
                        assessment2_id INTEGER NOT NULL,
                        status VARCHAR(20) DEFAULT 'pending',
                        admin_notes TEXT,
                        draft_email TEXT,
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                        finalized_at TIMESTAMP, user1_email_content TEXT, user2_email_content TEXT,
                        FOREIGN KEY (user1_id) REFERENCES user(id),
                        FOREIGN KEY (user2_id) REFERENCES user(id),
                        FOREIGN KEY (assessment1_id) REFERENCES assessment(id),
                        FOREIGN KEY (assessment2_id) REFERENCES assessment(id)
                    );
CREATE TABLE event (
	id INTEGER NOT NULL, 
	title VARCHAR(200) NOT NULL, 
	description TEXT NOT NULL, 
	location VARCHAR(500) NOT NULL, 
	date_time DATETIME NOT NULL, 
	price FLOAT, 
	picture VARCHAR(200), 
	created_at DATETIME, 
	created_by INTEGER NOT NULL, max_capacity INTEGER, kiosk_token VARCHAR(100), kiosk_token_expiry DATETIME, address TEXT, end_time DATETIME, price_max FLOAT, is_matchmaking BOOLEAN NOT NULL DEFAULT 0, 
	PRIMARY KEY (id), 
	FOREIGN KEY(created_by) REFERENCES user (id)
);
CREATE TABLE event_rsvp (
	id INTEGER NOT NULL, 
	event_id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT unique_event_rsvp UNIQUE (event_id, user_id), 
	FOREIGN KEY(event_id) REFERENCES event (id), 
	FOREIGN KEY(user_id) REFERENCES user (id)
);
CREATE TABLE event_check_in (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        event_id INTEGER NOT NULL,
                        user_id INTEGER NOT NULL,
                        checked_in_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                        had_rsvp BOOLEAN DEFAULT 0,
                        is_walk_in BOOLEAN DEFAULT 0,
                        FOREIGN KEY (event_id) REFERENCES event (id),
                        FOREIGN KEY (user_id) REFERENCES user (id),
                        UNIQUE (event_id, user_id)
                    );
CREATE TABLE event_energy_exchange (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            event_id INTEGER NOT NULL REFERENCES event(id),
            user_id INTEGER NOT NULL REFERENCES user(id),
            indicated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            confirmed BOOLEAN DEFAULT 0,
            amount_confirmed FLOAT,
            admin_notes VARCHAR(500)
        );
CREATE TABLE event_matchmaking_draft (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    event_id INTEGER NOT NULL REFERENCES event(id),
    user1_id INTEGER NOT NULL REFERENCES user(id),
    user2_id INTEGER NOT NULL REFERENCES user(id),
    notes TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, card1_id INTEGER REFERENCES event_board_card(id), card2_id INTEGER REFERENCES event_board_card(id));
CREATE TABLE event_user_board_position (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    event_id INTEGER NOT NULL REFERENCES event(id),
    user_id INTEGER NOT NULL REFERENCES user(id),
    pos_x REAL DEFAULT 100.0,
    pos_y REAL DEFAULT 100.0,
    UNIQUE (event_id, user_id)
);
CREATE TABLE event_board_card (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    event_id   INTEGER NOT NULL REFERENCES event(id),
    user_id    INTEGER NOT NULL REFERENCES user(id),
    pos_x      REAL    DEFAULT 100.0,
    pos_y      REAL    DEFAULT 100.0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE service (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name VARCHAR(200) NOT NULL,
            price_display VARCHAR(200),
            description TEXT,
            sort_order INTEGER NOT NULL DEFAULT 0,
            is_active BOOLEAN NOT NULL DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        );
DELETE FROM sqlite_sequence;
COMMIT;
