ency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Responsible",\n  "wrapping_up_ideal_friend_words_word3": "Understanding",\n  "wrapping_up_what_want_receive": "Support, community, idk",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "Ages 18-22",\n  "wrapping_up_open_to_multiple_matches": [\n    "No, I prefer to focus on one match at a time",\n    "No, I prefer to focus on one match at a time"\n  ]\n}','\n',char(10)),0,NULL);
