nflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "That I can be reactive but it\u2019s coming from not expressing my needs so I\u2019ve gotten better these past couple of years. Sometimes we take things personal rather than trying to understand each other so vulnerability is necessary to understand and empathy",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Creativity",\n    "Growth",\n    "Honesty",\n    "Love",\n    "Purpose",\n    "Self-awareness",\n    "Self-expression",\n    "Stability",\n    "Vulnerability",\n    "Wisdom"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should challenge me to grow",\n    "I value reliability and follow-through"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Pure honesty, taking accountability, Communication. Certainty within themselves",\n  "friendship_values_dealbreakers": "Dishonesty, inconsistency, lack of integrity",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Authentic",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Fun",\n  "wrapping_up_what_want_receive": "Motivation, community, support, fun activities, connections,",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman",\n    "Non-binary",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "28+",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(14,29,replace('{\012  "tell_us_more_what_brings_you": "I moved to Charlotte this year and am looking to grow my social circle. I am a 2nd year teacher who thrives off of quality friendships",\012  "friendship_readiness_emotional_availability": "8",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": "N/A",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Making time even when we get busy to spend quality time together even if we aren\u2019t together physically in the same room (sending texts, memes, care packages, etc.) I am big on doing activities especially when I am just getting to know someone (thrifting, nature walk, something to bond over)",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Share openly and engage actively with most people",\012  "personality_social_style_ideal_hangout_0": "3",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Primarily in-person hangouts",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "Quality time together to reconnect",\012    "Acts of care and presence",\012    "Time and space before reconnecting",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\012  "conflict_repair_friendship_lessons": "I love to be there/give into my friendships. Wether that be monetary or quality time I invest a lot of myself into friendships and if that is not reciprocated it can emotionally burn me out and I will avoid the person.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Yoga/Pilates",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Book clubs or discussion groups",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Learning new skills",\012    "Activism and social change",\012    "Nature connection and grounding"\012  ],\012  "hobbies_interests_doing_vs_being": "It depends",\012  "values_top_values": [\012    "Activism",\012    "Adventure",\012    "Animals",\012    "Fun",\012    "Genuineness",\012    "Fulfillment",\012    "Honesty",\012    "Community",\012    "Uniqueness",\012    "Thrift"\012  ],\012  "friendship_values_statements_resonate": [\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me",\012    "I value friends who share my worldview and values"\012  ],\012  "friendship_values_friendship_needs": [\012    "Shared laughter and lightness",\012    "Celebration of wins and joys",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences"\012  ],\012  "friendship_values_non_negotiables": "Must haves: positive attitude, kindness, willing to actually hangout, humor",\012  "friendship_values_dealbreakers": "No trump supporters please! They can be conservative but must have good morals (pro-LGBTQ, anti-ICE, disability inclusive, etc.). \n\nother dealbreakers: cannot joke/too serious all the time, caring too much about monetary things",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Once a week",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "Jokester",\012  "wrapping_up_ideal_friend_words_word2": "Trustworthy",\012  "wrapping_up_ideal_friend_words_word3": "Empathy",\012  "wrapping_up_what_want_receive": "Positive, like minded people who I can hangout with and not be anxious around",\012  "wrapping_up_gender_preference": "No preference",\012  "wrapping_up_age_preference": "Similar age to me, but not too picky on this (no older than 32 unless we are SUPER similar)",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,24);
INSERT INTO assessment VALUES(15,30,replace('{\n  "tell_us_more_what_brings_you": "I moved back to Charlotte. Looking to expand my horizons and meet new people. Connecting with like minded souls.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I am aware of patterns but haven''t worked through them yet",\n  "friendship_readiness_life_circumstances": "Major career transition",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Showing up means making time for people whether it\u2019s checking in through a call. Carving out time in your schedule to have lunch or grab a coffee. It\u2019s the intention. It\u2019s sharing yourself with someone whether sharing time, sharing words, etc.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "2",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Video calls",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acts of care and presence"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I think in past friendships I didn\u2019t voice my needs enough and I would grow bitter/resentful when those needs weren\u2019t met. In turn, it was hard for me to move past things. And I would hold grudges sometimes unconsciously. I also held back because I didn\u2019t want to make other people upset. Because in my my mind upset=lashing out= danger",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Rock climbing/adventure sports",\n    "Writing (journaling, poetry, books)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Nature connection and grounding",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Adventure",\n    "Social Justice",\n    "Creativity",\n    "Nature",\n    "Genuineness",\n    "Trust",\n    "Community",\n    "Love",\n    "Passion",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should challenge me to grow",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "must be open to trying new food/restaurants. can\u2019t do chicken tender people.",\n  "friendship_values_dealbreakers": "chronically neutral. you can never pick an opinion or stance on something. always wants to play middle ground",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Physical touch (hugging, holding hands)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "creative",\n  "wrapping_up_ideal_friend_words_word2": "honest",\n  "wrapping_up_ideal_friend_words_word3": "caring",\n  "wrapping_up_what_want_receive": "being understood and embraced. i want to feel supported but also held accountable. I want to feel like i\u2019m being challenged to discover different versions of myself.",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "no one under 22",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,107);
INSERT INTO assessment VALUES(16,31,replace('{\n  "tell_us_more_what_brings_you": "Hi! :) Over the past 5 years, I have been living in my hometown (Fayetteville), but I feel I have become more and more closed off from others. Most people I know or grew up here moved away, for one, after high school. While I was in school, I enjoyed the engagement and interaction, even if it was minimal. Since I\u2019m in a relationship, own a home, and am fully into my career, it has been much harder to make friends. I\u2019m used to meeting people through friends that know someone else, but I don\u2019t have many that I can say I formed on my own. I typically spend time with my parents and boyfriend, but I want more than that (I would love opportunities to double date, though!) I\u2019m tired of every day feeling the same w/o much spark or pizazz. When I see fun times on social media, I often find myself yearning for similar experiences, and I want to focus on creating them as a goal for next year. Financially, it has been hard for my bf and I to enjoy certain activities together, so I often just stay",\n  "friendship_readiness_emotional_availability": "6",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I am aware of patterns but haven''t worked through them yet",\n  "friendship_readiness_life_circumstances": "Other",\n  "friendship_readiness_life_circumstances_other_text": "Just the struggle with balancing between how much time I spend with my partner and with friends w/o feeling anxious or guilty",\n  "friendship_readiness_life_circumstances_details": "I think I pretty much answered it in the first question, but like I said before, I often find myself feeling anxious or stressed when people make plans because I worry about how my partner will feel and how much time I will need to work on this on my own. He supports me in going out and making connections, but I still don\u2019t feel confident because of past events. We are working on accepting that we won\u2019t always be with each other, but he\u2019s also not the type to have many friends, and a few of my friends still don\u2019t really know him, though we been together for 5+ years. It\u2019s like he exists but doesn\u2019t at the same time, which makes me feel uneasy when I approach that I\u2019m going out with x friend.",\n  "friendship_readiness_showing_up": "Energy, vulnerability, patience, understanding/empathy, sometimes putting in a little more effort when you notice I start pulling away or ghosting.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I need to be able to spread myself equally and not overextend too much in one area whether it is friendship or my relationship. Also, I must be willing to take the initiative and check in sometimes, even when I notice the other may not have done it in a while. I\u2019m the type of person to pick up where we left off like it was yesterday even life be lifeing, but I want more meaningful and genuine conversations and connections. I think that would help lessen my anxiety when I want to make plans or approach people.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Rock climbing/adventure sports",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Astrology",\n    "Religious gatherings (temple/church/mosque, etc)",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Social Justice",\n    "Peace",\n    "Empathy",\n    "Fun",\n    "Genuineness",\n    "Trust",\n    "Patience",\n    "Self-expression",\n    "Uniqueness",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "I need friends who can hold space for my emotions",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Someone who understands when I may be down or pulling away and takes the time out to meet me where I am at, respecting my space and creating space for my emotions, a good planner, willingness to get to know my partner for who he is (he\u2019s much more introverted than me, observes a lot, and offers little initially until you gauge his interest) and when we are together.",\n  "friendship_values_dealbreakers": "Someone who is close-minded and doesn\u2019t stand up for what is right or wrong, belittling, making me choose sides, taking my space or lack of engagement personal without attempting to check in.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Motivating",\n  "wrapping_up_ideal_friend_words_word2": "Entertaining/fun",\n  "wrapping_up_ideal_friend_words_word3": "Emotionally vulnerable/available",\n  "wrapping_up_what_want_receive": "I would like to receive long lasting friendships and genuine interest and conversation. I want someone to know me, my partner, and my family if at all possible, as I would like to be that person for someone else.",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "Similar age to me (26), but really truly, there is no preference. For example- I have many coworkers that are older than me, and we get along great! I like having a versed mix, but what is most important to me is I definitely want a good group to hang out with from time to time while building individual relationships.",\n  "wrapping_up_open_to_multiple_matches": [\n    "I''m not sure",\n    "I''m not sure"\n  ]\n}','\n',char(10)),1,73);
INSERT INTO assessment VALUES(17,35,replace('{\n  "tell_us_more_what_brings_you": "I\u2019ve recently found myself hanging around people who don\u2019t necessarily align with me. i\u2019ve been in and out of diffrent friendships and i haven\u2019t been able to find someone who\u2019s the right \u201cmatch\u201d for me, i am looking for that here.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am exploring what friendship means to me in this season",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Other",\n  "friendship_readiness_life_circumstances_other_text": "I\u2019m not able to drive",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Someone who knows the little things about me and doing random acts of kindness without me having to ask. Consistency and showing up is something that is very important to me.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Set a boundary:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me that i often cut people out of my life first before trying to analyze the situation in depth or see it from the other party\u2019s POV. I would like to burn less bridges and set boundaries with people rather than immediately cutting people off.",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Activism and social change",\n    "Nature connection and grounding"\n  ],\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Activism",\n    "Social Justice",\n    "Peace",\n    "Empathy",\n    "Fun",\n    "Loyalty",\n    "Love",\n    "Purpose",\n    "Rationality",\n    "Responsibility"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "People who have the same world views/political beliefs as me, people who follow through with plans, and people who have a genuine care for others.",\n  "friendship_values_dealbreakers": "Flakiness, being judgmental, bad morals, and carelessness.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Loving",\n  "wrapping_up_ideal_friend_words_word2": "Strong",\n  "wrapping_up_ideal_friend_words_word3": "Understanding",\n  "wrapping_up_what_want_receive": "I\u2019m looking to find more positive connections in my life, I haven\u2019t made many new friends. i\u2019m really looking for people i can trust and deeply relate to.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "Similar age to me 19-24",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(18,36,replace('{\n  "tell_us_more_what_brings_you": "Currently, I am on my spiritual growth journey which has prompted me to seek out new relationships like minded people with similar beliefs, hobbies, and age group (21-24) as me. I am 21 years old, a current junior at the University of North Carolina at Charlotte and have been feeling lonely in a new city. my family lives in charleston, sc and I am looking to expand my friendgroup in charlotte.",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Recent/upcoming move",\n  "friendship_readiness_life_circumstances_details": "I am naturally an introverted, shy, and anxious person in social situations that hinders my ability to authentically express myself. I prefer quiet, small spaces when meeting new people especially moving to a bigger city so I can thrive.",\n  "friendship_readiness_showing_up": "Consistent communication, time and energy is shared equally (not one person giving more effort and other not), being able to have casual conversations to build trust towards vulnerable topics, being readily available to listen when I feel like crashing out, giving good, practical advice.",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "End the friendship \u2013 consistent flakiness is a dealbreaker for me.",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "My past friendships have taught me to be kinder to myself, acknowledge that some people will BULLY to get what they want so learn to trust yourself and be comfortable with yourself above all else. I have learned to set boundaries firmly and if not respected, leave the friendship. I have learned to be more patient with conflict.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Adventure",\n    "Harmony",\n    "Nature",\n    "Fun",\n    "Genuineness",\n    "Gratitude",\n    "Spirituality",\n    "Loyalty",\n    "Self-expression",\n    "Thrift"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "I value reliability and follow-through",\n    "I need friends who can hold space for my emotions"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Peace,Compassion, Loyalty, Trust, Respect, Reciprocality, Love",\n  "friendship_values_dealbreakers": "Lying, Gaslighting, Breadcrumbing, Lovebombing, Rudeness",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Grouded",\n  "wrapping_up_ideal_friend_words_word2": "Ambitious",\n  "wrapping_up_ideal_friend_words_word3": "Assertive",\n  "wrapping_up_what_want_receive": "What I\u2019d like to receive in friendship and community is genuine connection and consistency\u2014relationships where there\u2019s mutual effort, trust, and care over time. I value friendships that grow through regular communication, shared experiences, and showing up for one another. As I continue to branch out in this city, I\u2019m looking not just to meet people, but to build lasting friendships where there\u2019s space for honesty, support, and growth. I want to be part of a community where people are intentional about staying connected, and where I can also be a reliable and supportive friend in return.",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "similar age to me 21-24",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,NULL);
