INSERT INTO assessment VALUES(26,48,replace('{\n  "tell_us_more_what_brings_you": "I still consider myself \u201cnew\u201d to charlotte\u2014been here 2.5 years. I have found community through various events I\u2019ve attended and hosted. Even though I have made some friends here, I have also lost some. So, I am open to meeting some new people to see if I can find a new friend, maybe two!",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Major life transition (marriage, divorce, etc)",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Showing up for me goes beyond doing activities together, usually this is where friendship starts. As my friendship develops, I hope we\u2019re able to be there in times of hardship for one another, to listen and resolve if we hurt one another\u2019s feelings, and be there to nurture a new friendship at a pace that works for us both.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "2",\n  "personality_social_style_making_plans": "I need structure and advanced notice",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "That i am very proud at how I handle conflict with friends nowadays\u2014able to be direct, see other\u2019s perspectives, and apologize. Relationships are more important to me than the need to be right. I am now able to speak up about my feelings and talk about them with friends, even though being vulnerable is hard\u2014 it\u2019s what brings people closer.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Adventure",\n    "Peace",\n    "Creativity",\n    "Spirituality",\n    "Growth",\n    "Intuition",\n    "Non-conformity",\n    "Purpose",\n    "Self-awareness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should accept me exactly as I am",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance"\n  ],\n  "friendship_values_non_negotiables": "Same political views, ability to talk to me about hard feelings or topics or willingness to try to, someone who also values relationships over being right, self awareness",\n  "friendship_values_dealbreakers": "If they\u2019re republican/trump-supporting, if we have no shared likes or activities,",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Self aware",\n  "wrapping_up_ideal_friend_words_word2": "Mixed race",\n  "wrapping_up_ideal_friend_words_word3": "Witchy",\n  "wrapping_up_what_want_receive": "Space to show up as my authentic self, willingness to understand my perspective, ability to tell me their own perspective, opportunities for growth.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "Over 28 is preferred.",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,NULL);
