": "Shared values (accept me for who i am), respect, sense of humor,",\012  "friendship_values_dealbreakers": "consistent effort, reliability",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "funny",\012  "wrapping_up_ideal_friend_words_word2": "consistent",\012  "wrapping_up_ideal_friend_words_word3": "thoughtful",\012  "wrapping_up_what_want_receive": "I want to feel seen and feel connected to my community in charlotte.",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "similar age preference",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(29,50,replace('{\012  "tell_us_more_what_brings_you": "Hi! I\u2019m a single, queer mom, currently pregnant as a surrogate! 2025 was filled with a lot of endings for me (friendships, relationships, jobs, etc) and I am really hoping that this has cleared the way for aligned community and opportunities in my life.",\012  "friendship_readiness_emotional_availability": "7",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I am exploring what friendship means to me in this season",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": [\012    "Major career transition",\012    "Grief or loss",\012    "Ending a significant relationship",\012    "Major life transition (marriage, divorce, etc)"\012  ],\012  "friendship_readiness_life_circumstances_details": "I am pregnant (as a surrogate) and due at the beginning of March. My capacity - and energy - will be greater after the baby is out as well! I am also a solo parent, and have a 4 year old daughter who I share custody of",\012  "friendship_readiness_showing_up": "Showing up means showing up authentically and being open and honest about our needs and capacity. I don\u2019t expect to talk to someone every day (but am always happy if that happens organically!) but really value open communication and reassurance.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "3",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Written communication (text, letter, etc)",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "I will always hold so much love for people after endings and can recognize that something may not be right for us in the moment.",\012  "hobbies_interests_activities_interests": [\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Writing (journaling, poetry, books)",\012    "Music (playing, creating, deeply listening)",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Philosophy and deep conversations",\012    "Writing and reflection",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Astrology",\012    "Therapy/personal growth work",\012    "Medicinal herbs/substances"\012  ],\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Activism",\012    "Family (chosen or biological)",\012    "Fun",\012    "Spirituality",\012    "Community",\012    "Non-conformity",\012    "Purpose",\012    "Self-awareness",\012    "Vulnerability",\012    "Sexuality"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friendship is about celebrating each other''s wins",\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Non-judgment and acceptance",\012    "Genuineness"\012  ],\012  "friendship_values_non_negotiables": "Open and judgement free \nAuthentic \nHonest\nIntimacy",\012  "friendship_values_dealbreakers": "Close mindedness\nInauthenticity \nRigidness",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Authentic",\012  "wrapping_up_ideal_friend_words_word2": "Loving",\012  "wrapping_up_ideal_friend_words_word3": "Fun!",\012  "wrapping_up_what_want_receive": "Mutual aid and support \nAbility to be ourselves without judgement \nTime spent together \nSoul family",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "25+",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,NULL);
INSERT INTO assessment VALUES(30,41,replace('{\012  "tell_us_more_what_brings_you": "I\u2019ve been in Charlotte all my life and I\u2019ve never fully explored the city or the people. I\u2019m looking for my \u201cforever\u201d friend group\u2014the one I\u2019ve been manifesting. To build an emotionally rich, supportive community stemming from honesty and a desire for connection.",\012  "friendship_readiness_emotional_availability": "10",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": "Major career transition",\012  "friendship_readiness_life_circumstances_details": "N/A I am open to someone looking to take their friendship journey slow",\012  "friendship_readiness_showing_up": "The ability (and comfortability) to do the mundane together. Run errands. Try out a new exercise class. Do work in a cafe or library. It\u2019s about being there for people in the small scheme of things in addition to showing up emotionally (when available) during hardships.",\012  "personality_social_style_recharge_style": "2",\012  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Texting throughout the day",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Acknowledgement of impact and sincere apology"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "A lack of communication (on both ends) actively creates an irreparable crack in the friendship that\u2019s difficult to mend. Bottling up emotions leads to resentment.",\012  "hobbies_interests_activities_interests": [\012    "Yoga/Pilates",\012    "Writing (journaling, poetry, books)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Book clubs or discussion groups",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Writing and reflection",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards"\012  ],\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Career",\012    "Social Justice",\012    "Creativity",\012    "Genuineness",\012    "Growth",\012    "Inclusiveness",\012    "Loyalty",\012    "Purpose",\012    "Self-awareness",\012    "Self-expression"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Friendship is about celebrating each other''s wins",\012    "Humor and laughter are essential to friendship"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "Honesty \nHumor \nPassionate (about literally anything, even if I\u2019m not into it) \nInclusivity and social justice",\012  "friendship_values_dealbreakers": "Lying \nUnable to hold a conversation \nBigoted \nOverly pessimistic \nUnreliable",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Once a week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Unique",\012  "wrapping_up_ideal_friend_words_word2": "Intelligent",\012  "wrapping_up_ideal_friend_words_word3": "Compassionate",\012  "wrapping_up_what_want_receive": "To have a place of belonging.",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "Similar in age to me (21-32)",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,NULL);
INSERT INTO assessment VALUES(31,53,replace('{\n  "tell_us_more_what_brings_you": "A friend shared this event and it sounded interesting. I have friends moving away and Id like to meet new people. I enjoy having a good community of friends :)",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Making time to connect with friends and hear about their life. Supporting them in their journeys. Doing fun activities together.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "4",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "I have had very few friendship conflicts in the past. When they have come up, it was addressed calmly and maturely.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Sports (playing or watching)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Nature",\n    "Health",\n    "Animals",\n    "Fun",\n    "Spirituality"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Mutual effort and reciprocity matters to me",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Respect, kindness",\n  "friendship_values_dealbreakers": "Not being open minded",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ]