INSERT INTO assessment VALUES(32,21,replace('{\012  "tell_us_more_what_brings_you": "currently, I feel fulfilled in my friendships- but want to continue being intentional and having an open attitude towards others as I\u2019ve noticed I\u2019ve started to seclude or close myself off more. I am taking into account my own personal stuff and the capacity I mentally, emotionally, and physically have and give myself grace for that too.",\012  "friendship_readiness_emotional_availability": "4",\012  "friendship_readiness_time_energy_capacity": "Very limited capacity (life is a lot right now)",\012  "friendship_readiness_friendship_intention": "I am exploring what friendship means to me in this season",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": [\012    "Health challenges",\012    "Other"\012  ],\012  "friendship_readiness_life_circumstances_other_text": "Own mental health! As well as familial transitions/shifts occurring",\012  "friendship_readiness_life_circumstances_details": "Trying to balance it all! Figuring out how to prioritize what and how to communicate or be vulnerable in my circles",\012  "friendship_readiness_showing_up": "Grace! Kindness and maybe reassurance? However, reassurance can be tricky as that can fuel some of my ocd lol but I appreciate the understanding my friends provide",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Share openly and engage actively with most people",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "3",\012  "personality_social_style_ideal_hangout_3": "4",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Voice notes",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Get overwhelmed and withdraw",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "This has been an ongoing journey, which i believe i will continue to do as we all evolve and grow and might need each other in different ways. I\u2019ve definitely noticed an avoidant behavior but also people pleasing. Wanting to never upset the other person and when I myself feel threatened, in the past I\u2019ve noticed my defensiveness kick in.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Yoga/Pilates",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Rock climbing/adventure sports",\012    "Music (playing, creating, deeply listening)",\012    "Cooking/Baking",\012    "Fashion/Styling",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Book clubs or discussion groups",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Astrology",\012    "Therapy/personal growth work",\012    "Nature connection and grounding",\012    "Energy work/holistic practices",\012    "Other"\012  ],\012  "hobbies_interests_activities_interests_other_text": "Running errands together like grocery store or Gym!! Exercise clases or getting nails done!",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Ambition",\012    "Peace",\012    "Empathy",\012    "Health",\012    "Genuineness",\012    "Growth",\012    "Community",\012    "Integrity",\012    "Love",\012    "Wisdom"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Mutual effort and reciprocity matters to me",\012    "I value friends who share my worldview and values"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences"\012  ],\012  "friendship_values_non_negotiables": "Same worldview (not racist, homophobic, etc) \nKindness\nPatience and compassion \nRespecting my own space",\012  "friendship_values_dealbreakers": "Hmm maybe I need to learn my boundaries bc the previous question I would answer the same here lol. But personally, anyone as a Trump supporter or not open to different perspectives.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)",\012    "Other forms of support (problem-solving, providing resources like money/meals)"\012  ],\012  "logistics_connection_frequency": "I am open",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Funny",\012  "wrapping_up_ideal_friend_words_word2": "Compassionate",\012  "wrapping_up_ideal_friend_words_word3": "Intelligent",\012  "wrapping_up_what_want_receive": "Support- whether that\u2019s me needing space or understanding and one on one time in chiller environments",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "No preference",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,77);
INSERT INTO assessment VALUES(33,55,replace('{\n  "tell_us_more_what_brings_you": "I have been feeling so overwhelmed/overworking myself because of the medical college admission test (mcat); just trying to meet new people and connect with others.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I am aware of patterns but haven''t worked through them yet",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Health challenges",\n    "Ending a significant relationship"\n  ],\n  "friendship_readiness_life_circumstances_details": "N/A",\n  "friendship_readiness_showing_up": "Ensuring that both of us are good, safe and content. If my friend needed anything, I will make sure I be there; but if I cannot, make sure I express that.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Very blunt, trying to not be blunt because sometimes life happens; no need to bring the next person down.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Rock climbing/adventure sports",\n    "Writing (journaling, poetry, books)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Writing and reflection",\n    "Therapy/personal growth work",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Peace",\n    "Creativity",\n    "Health",\n    "Generosity",\n    "Growth",\n    "Trust",\n    "Leadership",\n    "Self-awareness",\n    "Self-expression",\n    "Uniqueness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I appreciate friends who respect my need for space",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "integrity!",\n  "friendship_values_dealbreakers": "i am not sure.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "genuine",\n  "wrapping_up_ideal_friend_words_word2": "trust worthy",\n  "wrapping_up_ideal_friend_words_word3": "lovely",\n  "wrapping_up_what_want_receive": "guidance!",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "no preference, I am 26 if that help.",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(34,56,replace('{\012  "tell_us_more_what_brings_you": "I\u2019ve had a challenging time building genuine friendships since moving to Charlotte. As I\u2019ve stepped more fully into acting and modeling, my life has become very creative-driven, fast-paced, and passion-focused, and I\u2019ve realized how important it is to have friends who truly understand and respect that.\n\nI\u2019m looking for community with people who know what it means to chase something you love \u2014 people who understand being busy, working odd hours, and pouring your energy into creative growth. It\u2019s not just about being understood, but feeling supported and respected in that pursuit.\n\nI\u2019m hoping to find friendships rooted in mutual encouragement, creativity, and emotional maturity \u2014 a space where ambition and connection can coexist, and where community feels intentional and nourishing.",\012  "friendship_readiness_emotional_availability": "10",\012  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": [\012    "Major career transition",\012    "Grief or loss"\012  ],\012  "friendship_readiness_life_circumstances_details": "I also want to share that I help care for my brother, who is nonverbal and autistic. Since my dad passed, my mom has had to shift responsibilities, and that sometimes means my brother is part of my plans. I value friendships with people who are compassionate, flexible, and open to understanding that caregiving is part of my life. I\u2019m very mindful of my capacity and want to build friendships that are supportive, respectful, and grounded in mutual understanding.",\012  "friendship_readiness_showing_up": "Right now, showing up in a friendship looks like intentional time, honest communication, and mutual respect for each other\u2019s lives. I may not always be available on short notice, but when I commit, I genuinely show up \u2014 with presence, care, and follow-through.\n\nIt also means giving and receiving grace. I value consistency over constant contact, understanding over pressure, and the ability to be open about capacity, boundaries, and real life. Showing up looks like cheering each other on, respecting busy seasons, and being emotionally present when it matters most.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Share openly and engage actively with most people",\012  "personality_social_style_ideal_hangout_0": "2",\012  "personality_social_style_ideal_hangout_1": "3",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\012  "personality_social_style_communication_preference": [\012    "Texting throughout the day",\012    "Primarily in-person hangouts"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Written communication (text, letter, etc)",\012    "Acts of care and presence",\012    "Acknowledgement of impact and sincere apology"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Address it directly:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me that I can sometimes take things personally, especially when conflict feels unresolved. I\u2019m aware that past experiences with abandonment have made me want to address issues early, rather than letting them linger. I tend to reach for communication quickly because clarity helps me feel grounded and prevents misunderstandings from growing.\n\nI\u2019ve also learned that while I\u2019m actively working on giving situations space when needed, I show up fiercely for the people I care about. I value loyalty deeply, and I take pride in supporting my friends \u2014 whether that\u2019s hyping them up, advocating for them, or introducing them to spaces and people I genuinely believe will help them grow. I\u2019m learning to balance my desire for repair with patience, trust, and mutual understanding.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Writing (journaling, poetry, books)",\012    "Visual arts (painting, drawing, photography)",\012    "Music (playing, creating, deeply listening)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Fashion/Styling",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Book clubs or discussion groups",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Writing and reflection",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Astrology",\012    "Religious gatherings (temple/church/mosque, etc)",\012    "Therapy/personal growth work",\012    "Nature connection and grounding"\012  ],\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Social Justice",\012    "Creativity",\012    "Family (chosen or biological)",\012    "Genuineness",\012    "Growth",\012    "Community",\012    "Loyalty",\012    "Love",\012    "Responsibility",\012    "Self-awareness"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Friends should challenge me to grow",\012    "I value friends who share my worldview and values"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "My non-negotiables in friendship are open communication, emotional honesty, and consistency. I value relationships where people feel comfortable being themselves without walking on eggshells or projecting past hurts onto the present.\n\nClear, direct communication is essential to me \u2014 avoiding issues or refusing to talk things through isn\u2019t something I can sustain long-term. I also value authenticity; I want friendships where people show up as the same version of themselves across spaces, rather than shifting depending on who they\u2019re with. Mutual respect, self-awareness, and emotional accountability matter deeply to me.",\012  "friendship_values_dealbreakers": "My dealbreakers are passive communication, emotional inconsistency, and unresolved projection from past relationships. I struggle with friendships where issues are avoided rather than addressed, or where accountability and honesty are missing.\n\nI also find it unsustainable when someone presents very different versions of themselves depending on the people or environments they\u2019re in, or when there\u2019s a lack of respect for boundaries, time, or emotional effort. I value growth, self-awareness, and mutual care \u2014 without those, a friendship can\u2019t stay healthy for me.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Multiple times per week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Authentic",\012  "wrapping_up_ideal_friend_words_word2": "Passionate",\012  "wrapping_up_ideal_friend_words_word3": "Creative",\012  "wrapping_up_what_want_receive": "I\u2019m looking to receive consistency, understanding, and genuine encouragement in friendship and community. I value spaces where support goes both ways \u2014 where people celebrate each other\u2019s wins, show up during harder seasons, and respect one another\u2019s time, boundaries, and ambitions.\n\nI\u2019m hoping for community that feels emotionally safe, creatively inspiring, and rooted in mutual care \u2014 friendships where I can both give and receive support, grow alongside others, and feel truly seen without having to shrink or explain myself.",\012  "wrapping_up_gender_preference": "No preference",\012  "wrapping_up_age_preference": "No preference. Everyone has a story no matter what their age and I feel like I would like to get to know anyone you deem fit!",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,NULL);
