INSERT INTO assessment VALUES(36,58,replace('{\n  "tell_us_more_what_brings_you": "I am unemployed looking for work. I am almost 24, I have spent time in solitude figuring out who I am and my purpose and as much as I like my alone time, I yearn for a good community and nice friends",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am exploring what friendship means to me in this season",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Grief or loss"\n  ],\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "I am definitely trying to balance my personal life with my business but it\u2019s definitely time for me to see where I am in life with meaningful connections",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "1",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "My past friendships have taught me to stick to my boundaries and to take care of myself and to find a balance of expressing how I feel and receiving feedback on how I\u2019ve made them feel",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Sports (playing or watching)",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Beauty",\n    "Social Justice",\n    "Creativity",\n    "Spirituality",\n    "Love",\n    "Self-awareness",\n    "Self-expression",\n    "Uniqueness",\n    "Vulnerability",\n    "Wisdom"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "Someone who is open minded and in touch with their creativity  and impact in the world",\n  "friendship_values_dealbreakers": "Someone who is close minded. Lacks accountability. Deeply Religious (Indoctrination)",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Reliable",\n  "wrapping_up_ideal_friend_words_word2": "Honest",\n  "wrapping_up_ideal_friend_words_word3": "Compassionate",\n  "wrapping_up_what_want_receive": "A reflection of who I am and what I bring to the collective and universe. I would like to receive confirmation that I am deserving of a community. People that I can truly connect with",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "24-35",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
