osed off, \u201cmy way or the highway\u201d, strict, rude, arrogant",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Chill",\n  "wrapping_up_ideal_friend_words_word2": "Open",\n  "wrapping_up_ideal_friend_words_word3": "Unique",\n  "wrapping_up_what_want_receive": "Friends to Family",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "21+",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,NULL);
INSERT INTO assessment VALUES(42,66,replace('{\n  "tell_us_more_what_brings_you": "I moved to Greensboro after graduating from college. I work from home, so it\u2019s hard to meet people, but I saw one of your Tiktok\u2019s!",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "I\u2019m an introvert so it takes me a minute to warm up to people, but I love quality time, so once I\u2019m comfortable around someone I can fully be myself",\n  "friendship_readiness_showing_up": "I think it means doing small things to make sure your friends know you care and want the best for them. That, and being flexible if they need you",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "2",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I\u2019ve learned that if a friend puts you down, even in passive aggressive ways, that\u2019s not your friend. Those types of friendships used to make me insecure, but now I feel more confident to call it out when I see it",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Creativity",\n    "Health",\n    "Genuineness",\n    "Growth",\n    "Independence",\n    "Community",\n    "Love",\n    "Purpose",\n    "Self-awareness",\n    "Self-expression"\n  ],\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "I value reliability and follow-through",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "My non-negotiables for friendship would have to be that I have fun and have a good time around my friends",\n  "friendship_values_dealbreakers": "My dealbreakers would be constant negativity or someone against growth",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Funny",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Loyal",\n  "wrapping_up_what_want_receive": "I\u2019d like to feel like I\u2019m a part of a little group or network of people that make me smile and uplift each other",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "Similar age to me ideally, or older",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,NULL);
INSERT INTO assessment VALUES(43,67,replace('{\n  "tell_us_more_what_brings_you": "Moved to Charlotte after grad school about a year ago and got super caught up in work and trying to build a career that I haven\u2019t had the time to make friends and make the city feel like home. Looking for my community, my support system, basically people who will be my ride or dies!",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "My work schedule can be a little hectic with 3/4 weeks a month being over 50 hours a week but I\u2019m looking for friends to hang out with on the weekends and am happy to make time for the right people outside of that",\n  "friendship_readiness_showing_up": "Quality time is one of my top love languages. I\u2019m looking for emotionally intelligent friends who prioritise the people in their lives and who are uplifting and supportive!",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": "A direct conversation about what happened",\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me to be better about open communication and bringing up issues that may bother me before it turns to silent resentment. I\u2019ve also learnt that it\u2019s important to find people who show up for me just as much as I do for them and that make me feel like I\u2019m a priority in their lives as well",\n  "hobbies_interests_activities_interests": [\n    "Visual arts (painting, drawing, photography)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Philosophy and deep conversations",\n    "Therapy/personal growth work"\n  ],\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Ambition",\n    "Empathy",\n    "Family (chosen or biological)",\n    "Genuineness",\n    "Growth",\n    "Community",\n    "Loyalty",\n    "Self-awareness",\n    "Stability",\n    "Work Ethic"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "I need friends who can hold space for my emotions",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Emotional intelligence and feeling comfortable being myself around them. Like it feels easy and natural and recharging to be around them",\n  "friendship_values_dealbreakers": "Unreliability, not in tune with their emotions, when effort isn\u2019t mutual, when they are too conflict resistant and bad at communicating",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Intelligent",\n  "wrapping_up_ideal_friend_words_word2": "Loyal",\n  "wrapping_up_ideal_friend_words_word3": "Kind",\n  "wrapping_up_what_want_receive": "I\u2019m looking for a support system and people to share hobbies with and to spend time with",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "20s or mid to late 20s ideally but open to other age groups depending on the situation",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,135);
