ies_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Rock climbing/adventure sports",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Religious gatherings (temple/church/mosque, etc)",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Adventure",\n    "Beauty",\n    "Career",\n    "Peace",\n    "Health",\n    "Forgiveness",\n    "Genuineness",\n    "Fulfillment",\n    "Spirituality",\n    "Responsibility"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I appreciate friends who respect my need for space",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation"\n  ],\n  "friendship_values_non_negotiables": "Respect, open-mindedness and honest.",\n  "friendship_values_dealbreakers": "N/a",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Collaborative",\n  "wrapping_up_ideal_friend_words_word2": "Adventures",\n  "wrapping_up_ideal_friend_words_word3": "Relaxed",\n  "wrapping_up_what_want_receive": "New connections",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman"\n  ],\n  "wrapping_up_age_preference": "",\n  "wrapping_up_open_to_multiple_matches": [\n    "No, I prefer to focus on one match at a time",\n    "No, I prefer to focus on one match at a time"\n  ]\n}','\n',char(10)),1,60);
INSERT INTO assessment VALUES(53,79,replace('{\n  "tell_us_more_what_brings_you": "I moved to Charlotte a couple months ago and always looking to expand my circle!",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "I may travel for work frequently but always home on the weekends",\n  "friendship_readiness_showing_up": "Being honest and communicative",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "4",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "I prefer less frequent but more meaningful exchanges",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "They taught me how to speak on issues. I used to let things boil over and I would explode and regret it shortly after. Now I think on my feelings and let people know how I\u2019m feeling in calm way without letting it consume me.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Sports (playing or watching)",\n    "Visual arts (painting, drawing, photography)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Career",\n    "Animals",\n    "Fun",\n    "Genuineness",\n    "Honesty",\n    "Independence",\n    "Self-awareness",\n    "Risk-taking",\n    "Wisdom"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "I value reliability and follow-through",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Accountability and growth",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "Must be kind, honest, and down to do a bunch of random activities with me. And I always prefer people who laugh at my jokes :)",\n  "friendship_values_dealbreakers": "People too absorbed by the media (and social media) I like to live in the moment and don\u2019t want someone who is so invested in their online image.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Humorous",\n  "wrapping_up_ideal_friend_words_word3": "Adventurous",\n  "wrapping_up_what_want_receive": "People to do activities with last minute. Any event is exciting to me",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman"\n  ],\n  "wrapping_up_age_preference": "Similar to me so 24-33",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(54,80,replace('{\n  "tell_us_more_what_brings_you": "I graduated from my Masters program recently and moved to Charlotte around June of 2025. Would love to make new friends as I\u2019be been settling into the new city!",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Major career transition"\n  ],\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "It 100% depends on the wavelength that both of us are in! My version of showing up for a friend can be interpreted differently by them so I always want to ask first. For example showing up could mean cheering my friend on during a marathon, but she also maybe wants to have a wine and yap sesh. Everyone\u2019s \u2018showing up\u2019 looks different and it\u2019s important for me to cater to that.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "1",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "That self-introspection and reflection never has an end-goal! Every day is a continuous process of self improvement",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Sports (playing or watching)",\n    "Visual arts (painting, drawing, photography)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Fashion/Styling",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Therapy/personal growth work"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Ambition",\n    "Assertiveness",\n    "Beauty",\n    "Career",\n    "Empathy",\n    "Family (chosen or biological)",\n    "Forgiveness",\n    "Generosity",\n    "Independence",\n    "Leadership"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friendship is about celebrating each other''s wins",\n    "I value reliability and follow-through"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability"\n  ],\n  "friendship_values_non_negotiables": "Someone who I can rely on to be there for me through all the highs and lows of life. Someone who I can hope and pray for their success and feel reciprocated.",\n  "friendship_values_dealbreakers": "Someone who is jealous, male-centered, too materialistic, non self-aware of how their actions impact others",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Warm",\n  "wrapping_up_ideal_friend_words_word2": "Kind",\n  "wrapping_up_ideal_friend_words_word3": "Celebratory",\n  "wrapping_up_what_want_receive": "A safe space to be vulnerable and accepted for who I am",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "Similar age to me, younger than 30 older than 23",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(55,18,replace('{\n  "tell_us_more_what_brings_you": "I\u2019m seeking friends that love to spend a lot of in between time together (eg. can be together and do nothing and enjoy it). As an adult that is harder to come by because we are all working so much!",\n  "friendship_readiness_emotional_availability": "5",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Other"\n  ],\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "For me spending regular time in person is a big factor that I prefer/prioritize (vs. texting)",\n  "personality_social_style_recharge_style": "5",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\n  "personality_social_style_communication_preference": [\n    "Voice notes",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "I prefer less frequent but more meaningful exchanges",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "I have learned that for me it is very possible to go through periods of disconnection with friends and feel hurt for a while and still reconnect after depending on the situation so I am incredible slow to end a friendship. In fact I don\u2019t think I\u2019ve ever ended a friendship, just have had to set certain boundaries in terms of closeness with some in order to maintain a relationship. I am able to maintain long distance friendships but because I have multiple long distance friend groups it is realistically not possible to have them all on the same level of investment so some have naturally waned depending on each of our lives. Early in my life I had friendships where others were consistently relying on me for emotional and practical support and I was not relying on them at all - it was imbalanced and resembled codependency as I wanted to be needed. After high school I worked through this pattern and built non codependent friendships in college and beyond. Sometimes that pattern pops up dep",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Writing (journaling, poetry, books)",\n    "Music (playing, creating, deeply listening)",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Religious gatherings (temple/church/mosque, etc)",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Activism",\n    "Adventure",\n    "Ambition",\n    "Assertiveness",\n    "Beauty",\n    "Career",\n    "Social Justice",\n    "Harmony",\n    "Peace",\n    "Empathy"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value reliability and follow-through",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Actively working to be anti racist, intersectionally feminist, queer affirming (will state out loud that they are working toward those things and always will be)",\n  "friendship_values_dealbreakers": "The opposite of the previous question. Also if their words and actions don\u2019t align.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "High level of integrity",\n  "wrapping_up_ideal_friend_words_word2": "Fun and weird and silly",\n  "wrapping_up_ideal_friend_words_word3": "Gentle",\n  "wrapping_up_what_want_receive": "Integrity, thoughtfulness, spontaneity, fun/weird/laughter, compassion",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "26-35",\n  "wrapping_up_open_to_multiple_matches": [\n    "I''m not sure",\n    "I''m not sure"\n  ]\n}','\n',char(10)),1,99);
INSERT INTO assessment VALUES(56,83,replace('{\n  "tell_us_more_what_brings_you": "I\u2019ve always been drawn towards the Occult but have never dove fully into it and I would love to find more friends that love it as well. I would love to learn more from my community and I feel like it would make me more comfortable in accepting this part of myself.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Grief or loss",\n    "Major life transition (marriage, divorce, etc)"\n  ],\n  "friendship_readiness_life_circumstances_details": "Even though I have gone through a lot within the recent years, I am still very open. I would just prefer a slow one.",\n  "friendship_readiness_showing_up": "Seeing each other at least once a month and learning about each other and our hobbies and our aligned interests. Sharing our knowledge.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "1",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Video calls",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I tend to stay in friendships that I have outgrown and have grown to be very unhealthy. My friendships impact me a lot so I don\u2019t have an easy time speaking up for myself and how I feel but I am working on that.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "It depends",\n  "values_top_values": [\n    "Ambition",\n    "Career",\n    "Social Justice",\n    "Empathy",\n    "Creativity",\n    "Generosity",\n    "Genuineness",\n    "Growth",\n    "Purpose",\n    "Self-expression"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should accept me exactly as I am",\n    "Mutual effort and reciprocity matters to me",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "People that want to explore and grow. People with a passion for living and learning",\n  "friendship_values_dealbreakers": "Critical and nitpicky. It\u2019s exhausting to be around",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Generous",\n  "wrapping_up_ideal_friend_words_word2": "Passionate",\n  "wrapping_up_ideal_friend_words_word3": "Adventurous",\n  "wrapping_up_what_want_receive": "A sense of love, belongingness and acceptance.",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "No preference!",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,114);
INSERT INTO assessment VALUES(57,82,replace('{\n  "tell_us_more_what_brings_you": "I feel like community is more important now than ever, and I\u2019ve never been super intentional about \u201cbuilding my community\u201d as I was in the service industry for so long it just came with its own community built in. Now I\u2019m older and currently in my confusing post break up healing era and looking for more like minded souls that engage in activities that aren\u2019t always centered around drinking.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am unsure",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Ending a significant relationship"\n  ],\n  "friendship_readiness_life_circumstances_details": "I\u2019m having to be a bit financially creative in this season so may opt for free or low cost activities.",\n  "friendship_readiness_showing_up": "I do value consistency and want to be clear that energy levels are a little low right now, but come spring I love to be outside!",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "I am a sensitive sally. And if I\u2019m feeling hurt I might take a minute to collect myself and then I\u2019ll ask for a conversation to be direct, I don\u2019t like to drag things out. Also, just a general tendency to isolate if I\u2019m overwhelmed.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Sports (playing or watching)",\n    "Rock climbing/adventure sports",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Adventure",\n    "Creativity",\n    "Nature",\n    "Genuineness",\n    "Spirituality",\n    "Growth",\n    "Honesty",\n    "Love",\n    "Uniqueness",\n    "Thrift"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I appreciate friends who respect my need for space",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Intellectual stimulation",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "I have a high standard for personal integrity but like no one here is going to be a shitty person right. Like attracts like but yeah, no trump clowns, no hate or disrespect to other humans of any kind.",\n  "friendship_values_dealbreakers": "I\u2019m tired of always being the initiator or planner. I\u2019m finding myself at home filling this out because I feel like I don\u2019t see my friends unless I host (which I enjoy) or plan something. So please have equal initiative, reciprocity is hot. Transparency and honesty are also a must because we\u2019re grown, I\u2019ll always take the hard truth over an easy lie.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Chill",\n  "wrapping_up_ideal_friend_words_word3": "Goofy",\n  "wrapping_up_what_want_receive": "LOVE. IVE GOT LOVE TO GIVE AND HUGS TO BE HUGGED WERE WASTING TIME HERE",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "No preference",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,NULL);
INSERT INTO assessment VALUES(58,84,replace('{\012  "tell_us_more_what_brings_you": "I''ve been seeking quality friendships with other women. I currently have a lot of shallower relationships and I''m looking for more. I want to expand my community. I''ve struggled finding deeper friendships with people who show up in the same way I am, or who are looking for a deeper friendship.",\012  "friendship_readiness_emotional_availability": "10",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": "Major career transition",\012  "friendship_readiness_life_circumstances_details": "While I''m the middle of a career transition, I''m currently looking for work so have a lot of free time",\012  "friendship_readiness_showing_up": "It looks like consistency, honesty, and reciprocating the same energy I am giving out. It''s understanding friendship isn''t always convenient but it''s worth it. Showing up is being there when someone needs you, being vulnerable about your needs and wants, and accepting your friends where they are at.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "3",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\012  "conflict_repair_friendship_lessons": "I''ve learned I can be  more direct and comfortable with conflict than others and that can make people feel uncomfortable when directly addressed. \nI''ve noticed I can be a lot more picky about my boundaries with friendships at this point in my life. Ive learned that it''s better to be honest and clear with expectations and hurts  with someone who is emotionally mature enough to hear it. I also have noticed if my boundaries or expectations get ignored over and over I have no problem dropping them as a friend.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Visual arts (painting, drawing, photography)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Cooking/Baking",\012    "Book clubs or discussion groups",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Astrology",\012    "Therapy/personal growth work",\012    "Nature connection and grounding",\012    "Energy work/holistic practices",\012    "Medicinal herbs/substances"\012  ],\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Empathy",\012    "Spirituality",\012    "Loyalty"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "I value reliability and follow-through",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Celebration of wins and joys",\012    "Consistency and reliability"\012  ],\012  "friendship_values_non_negotiables": "Consistency, honesty, reciprocity. Social justice and valuing community. Loves nature and is in touch with their spirituality.",\012  "friendship_values_dealbreakers": "Inconsistency, dishonesty, lack of mutual respect. Lack of communication. Conservative views. People who love gossip and focusing on the negativity in their life. People who don''t ask questions about my life.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)",\012    "Other forms of support (problem-solving, providing resources like money/meals)"\012  ],\012  "logistics_connection_frequency": "Multiple times per week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Consistent",\012  "wrapping_up_ideal_friend_words_word2": "Honest",\012  "wrapping_up_ideal_friend_words_word3": "Loyal",\012  "wrapping_up_what_want_receive": "I liked to receive support and adventure. Shared values and new experiences. Honesty and laughs.",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "Similar age to me. But no younger than 27",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,49);
INSERT INTO assessment VALUES(59,87,replace('{\n  "tell_us_more_what_brings_you": "Hi! I recently moved to Charlotte from St. Pete, FL in October. In short, making friends as an adult is harder than I remember. Charlotte already feels like home and I\u2019m excited to build my life here!",\n  "friendship_readiness_emotional_availability": "6",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I currently would like low-stakes connections",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Major career transition",\n    "Major life transition (marriage, divorce, etc)"\n  ],\n  "friendship_readiness_life_circumstances_details": "One of my passions is traveling, I\u2019ll pick up and go on a trip in less than a week\u2019s notice. Eventually I\u2019d love to do this with a friend, now mutual understanding in flexibility is really key for me.",\n  "friendship_readiness_showing_up": "Just down to hang and chat. I\u2019m more down for a moody bar with low lighting and lower background music to actually hear each other speak. Also life gets so hectic and the understanding of taking some hermit time is important to me to sustain a friendship.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I need structure and advanced notice",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Feel hurt but bottle it up and move on",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I have a hard time with taking space in conflict. Most of my friendships at this point are 5+ years and when conflict isn\u2019t resolved immediately it weighs on me more than I realize. They\u2019ve also taught me that I am eager to hear the other person\u2019s feelings to come to a resolution.",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Cooking/Baking",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Learning new skills",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "It depends",\n  "values_top_values": [\n    "Beauty",\n    "Empathy",\n    "Trust",\n    "Inclusiveness",\n    "Independence",\n    "Self-awareness",\n    "Sexuality"\n  ],\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "Humor and laughter are essential to friendship",\n    "I need friends who can hold space for my emotions"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "Laughter. Grace to make mistakes. Willingness to try something new and leave early if we hate it.",\n  "friendship_values_dealbreakers": "Harmful selfishness, a conversation can always be had. Close-mindedness. Anti-gossip.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Other forms of support (problem-solving, providing resources like money/meals)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "Monthly",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": [\n    "Talkative",\n    "Talkative"\n  ],\n  "wrapping_up_ideal_friend_words_word2": [\n    "Honest",\n    "Honest"\n  ],\n  "wrapping_up_ideal_friend_words_word3": [\n    "Friendly",\n    "Friendly"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(60,89,replace('{\n  "tell_us_more_what_brings_you": "I''m friends with Iris and am pumped to support her business but am also excited and eager to always make new friends, I''m a total extrovert and love to make new friends! I really am wanting to be more intentional about the community I surround myself with as well",\n  "friendship_readiness_emotional_availability": "6",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Other",\n  "friendship_readiness_life_circumstances_other_text": "just in a busier season",\n  "friendship_readiness_life_circumstances_details": "I am always eager to make new friends and welcome new connections but am also defintley needing flexibility as I feel very busy in this season",\n  "friendship_readiness_showing_up": "I think its energy, compassion, flexibility, and openess",\n  "personality_social_style_recharge_style": "5",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "4",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Written communication (text, letter, etc)",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "Defintley learning when to address things and checking in with people who may not voice their issues/hurt",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Music (playing, creating, deeply listening)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Activism and social change",\n    "Therapy/personal growth work"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Empathy",\n    "Family (chosen or biological)",\n    "Fun",\n    "Forgiveness",\n    "Inclusiveness",\n    "Community",\n    "Love",\n    "Resilience",\n    "Vulnerability",\n    "Work Ethic"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "To celebrate each other wins, not view friendship as a competition, respect and inclusive to other",\n  "friendship_values_dealbreakers": "talking behind each others backs, unable to apologize or see other friends perspective when hurt is brought up",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Compassionate",\n  "wrapping_up_ideal_friend_words_word2": "Respectful",\n  "wrapping_up_ideal_friend_words_word3": "Fun",\n  "wrapping_up_what_want_receive": "Shared support and communtiy",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "23-28 but really not a huge preferance on age but probably a similar life stage",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(61,94,replace('{\n  "tell_us_more_what_brings_you": "I am out of work and very isolated. I''ve been dealing with the rejection and anxiety of extended unemployment and job searching. Ive gone to meetups and other events but haven''t made a lot of lasting connections. Im introverted and its a challenge to go to new events but I try.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Grief or loss"\n  ],\n  "friendship_readiness_life_circumstances_details": "I worry about being a burden to my friends because I get depressed. Im dealing with real signifcant financial hardship and the burden of job interviewing so I worry that I''ll drive people away by being sad or negative.",\n  "friendship_readiness_showing_up": "Making an effort to follow up, keep in touch, and listen. Being available but not to the point where it negatively impacts your own mental health.",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Video calls"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": "A direct conversation about what happened",\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I haven''t really experienced a major friendship challenge. I feel like relationships have drifted apart rather than one specific incident.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Meditation/mindfulness",\n    "Therapy/personal growth work",\n    "Nature connection and grounding"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Harmony",\n    "Peace",\n    "Empathy",\n    "Creativity",\n    "Nature",\n    "Fun",\n    "Gratitude",\n    "Growth",\n    "Inclusiveness",\n    "Community"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Mutual support during hard times",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "non smoker non political or non trump fan sense of humor non judgement and acceptance open minded and kind",\n  "friendship_values_dealbreakers": "smoking, unkindness, selfishness, lack of empathy, lack of time for you, judgement, wanting to ''fix'' you, not listening, unavailable emotionally, intolerant",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "kind",\n  "wrapping_up_ideal_friend_words_word2": "empathetic",\n  "wrapping_up_ideal_friend_words_word3": "friendly",\n  "wrapping_up_what_want_receive": "emotional support, understanding, acceptance, nurturing, challenge to grow, fun/someone to go out with",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "similar age but open to all",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(62,98,replace('{\n  "tell_us_more_what_brings_you": "Moved to Charlotte to years ago with my 5 children and boyfriend we have no support no village. That change has put a drastic change in my role as a mom, taking full time mother to a new level. I\u2019m in search of my people.",\n  "friendship_readiness_emotional_availability": "6",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "I\u2019m an introvert at heart",\n  "friendship_readiness_showing_up": "Coming into a new friendship of course I understand there\u2019s feeling each others vibes and intentions but for the most part showing up to me involves the reciprocation of being dependable for one another feelings seen and considered or thought of and being actively involved or interested.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\n  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "That I\u2019m too nice, too thoughtful. I ignore red flags because I don\u2019t want to internalize and then get my feelings hurt from being right all along. I\u2019m looked at as being \u201cput together\u201d which is why no one is ever there for me.",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Fashion/Styling",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Peace",\n    "Empathy",\n    "Growth",\n    "Intuition",\n    "Loyalty",\n    "Self-awareness",\n    "Uniqueness",\n    "Solitude",\n    "Vulnerability",\n    "Wisdom"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Always making everything about themselves, not being able to take accountability, lack of reciprocation, dark humor, non-empathetic, people pleaser",\n  "friendship_values_dealbreakers": "Inconsistency, one-sidedness, narcissism",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Loyal",\n  "wrapping_up_ideal_friend_words_word2": "Interested",\n  "wrapping_up_ideal_friend_words_word3": "Active",\n  "wrapping_up_what_want_receive": "People the see me for who I truly am. Support and comfort",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman"\n  ],\n  "wrapping_up_age_preference": "24-36",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(63,99,replace('{\n  "tell_us_more_what_brings_you": "I\u2019m in a transitional period in my life and struggling to find friends - recently moved back to my hometown but planning on moving back closer to my besties - only thing is I need to first finish grad school (which has been a long struggle to being disabled and queer at a small Christian school) I\u2019m hoping to build community because I love being social and want to build connections to make it a little less lonely. I\u2019m also just interested in talking/getting to know people with similar experiences and communities :)",\n  "tell_us_more_political_leanings": "Leftist",\n  "tell_us_more_gender_identity": "Non-binary",\n  "tell_us_more_gender_identity_other_text": "I use any pronouns!",\n  "tell_us_more_about_yourself": "I am a social butterfly navigating sobriety + a love for dancing! I love talking about meaningful topics and learning more about other perspectives :) I always find something to learn - I\u2019m very open and compassionate for my neighbors and deeply love my friends!",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Major career transition"\n  ],\n  "friendship_readiness_life_circumstances_details": "I am excited to get to know others   and have plenty of time to chat but am always understanding of situations and others capacities that may affect availability to chat :) I\u2019m just happy to make new connections!",\n  "friendship_readiness_showing_up": "Vulnerability and consistency are the most important to me rn. I want to connect genuinely all the other things I am flexible",\n  "personality_social_style_recharge_style": "5",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Video calls",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "I\u2019ve noticed that friendships for me can be all in occasionally to a fault. I have had friendships that are perfect until they are not which I have reflected on and I think boundaries could have helped. After reflection, I noticed my dependence on friends can become overwhelming and harmful. Although now, after learning about my connection style, I try to make boundaries clear, have check-ins, and rely on myself more. Instead of feeling alone and anxious I have worked on my coping skills to be okay with alone time and practicing my coping skills",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Philosophy and deep conversations",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_hobbies_details": "I love journaling, crochet, and listening to a music in a spiritual way and when I\u2019m not in the mood I love dancing and going out and being social",\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Social Justice",\n    "Empathy",\n    "Creativity",\n    "Fun",\n    "Gratitude",\n    "Growth",\n    "Integrity",\n    "Self-awareness",\n    "Self-expression",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "I need a friend who is ready to be vulnerable and honest so that we can connect and grow",\n  "friendship_values_dealbreakers": "I cannot be friends with someone who is apolitical or scared to have conversations about the connections between systems or someone who is not questioning the oppressive systems we live in",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Open",\n  "wrapping_up_ideal_friend_words_word2": "Bold",\n  "wrapping_up_ideal_friend_words_word3": "Sensitive",\n  "wrapping_up_what_want_receive": "I am open to any connections or community that comes from this :)",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "23 and older",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,18);
INSERT INTO assessment VALUES(64,100,replace('{\n  "tell_us_more_what_brings_you": "I moved to Charlotte in September from Massachusetts, and I''ve needed to build up a new support system for myself. I work entirely from home, so it''s easy for me to keep my world really small.",\n  "tell_us_more_political_leanings": "Leftist",\n  "tell_us_more_gender_identity": "Gender not listed here",\n  "tell_us_more_gender_identity_other_text": "Gender-queer",\n  "tell_us_more_about_yourself": "I can tend to be a really awkward person, but once I''m comfortable around you, you''ll see the full range of my personality. I''m fiercely protective of my people, and always try my best to meet people where they''re at. My interests fall on the nerdier side, but I try to be open to a lot of different activities (except anything physical, I''m not athletic whatosever!) I''m the kind of person where we can get stuck with our own lives for 6 months, but when we see each other it''s like no time has passed at all.",\n  "friendship_readiness_emotional_availability": "6",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am exploring what friendship means to me in this season",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Major career transition"\n  ],\n  "friendship_readiness_life_circumstances_details": "I''m working to pursue licensure in my field of work, and am preparing for my exam at the end of June, so a lot of my free time is being taken up by studying for this exam. My partner also struggles with their mental health so being available for them has taken priority these past 6 months.",\n  "friendship_readiness_showing_up": "Showing up in a friendship means meeting the other person where they''re at, as well as them meeting me where I am. If one person needs space to recharge, that space is freely given. If one person is struggling more, the other person tries to give them grace (within reason). If one party is upset with the other, we''re not afraid to be honest about our hurt. With where I''m at with many of my friendships, we don''t get to speak very often, once per month maybe if I''m lucky, but when we spend time together we''re present with each other and don''t multitask or split our time.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "I have noticed plenty moments of growth for myself throughout adolescence and young adulthood in how I go about friendships. I had struggled previously with falling into \"favorite person\" patterns and neglecting other friendships, which taught me that all people are worthy of my attention and care, instead of dedicating myself so intensely to one person it''s okay to spread myself amongst a few people. I''ve also struggled with the impacts of my own mental health on friendships and my tendencies towards isolation as a coping strategy; it''s shown me that any interaction, no matter how small, is still meaningful. Even if it''s just a check-in text or a social media post that reminded me of them, it''s not too hard for me to do and it does really matter to some of my people.",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Therapy/personal growth work",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "It depends",\n  "values_top_values": [\n    "Career",\n    "Social Justice",\n    "Empathy",\n    "Genuineness",\n    "Integrity",\n    "Love",\n    "Passion",\n    "Self-awareness",\n    "Self-expression",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "I appreciate friends who respect my need for space",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "I do need someone who aligns in political beliefs. As I value my willingness to experiment with my friends'' interests, I hope they''d be open-minded with mine. I need a friend who can respect boundaries and isn''t afraid to set their own. If I''m struggling, I want to feel comfortable enough to tell my people this without feeling judged.",\n  "friendship_values_dealbreakers": "I need a friendship that takes my life, schedule, mood, and interests into account, and doesn''t unilaterally make decisions for the friendship. If we have plans to get together, I need my people to be reliable. If a person shows little respect to my life, my struggles, the things I value spending my time on, then I really struggle to form a comfortable connection with them.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Genuine",\n  "wrapping_up_ideal_friend_words_word2": "Understanding",\n  "wrapping_up_ideal_friend_words_word3": "Match-my-freak",\n  "wrapping_up_what_want_receive": "A support system that I''d be able to lean on in times of distress and struggle, as well as someone who will help me get out of the house more.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "Similar age to me, early- to late-20s",\n  "wrapping_up_open_to_multiple_matches": [\n    "I''m not sure",\n    "I''m not sure"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(65,101,replace('{\n  "tell_us_more_what_brings_you": "I went through a few friend breakups last year and I\u2019m moving to Charlotte in a few days. I really want to start building my community and being apart of one to show mutual support.",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I\u2019m a really happy person. I get excitable about the small things. I\u2019m a thoughtful and considerate woman who loves to try new things. I enjoy meeting new people though I will say I am shy at times. I do have a hard time approaching people though but I am always open to others approaching me.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "Recent/upcoming move",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Showing up means being emotionally available, vulnerable, consistent, and readiness to listen. These things are mutual.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I don\u2019t communicate as well as I though I did. I get passive aggressive and I often hold things that\u2019s bothering me about them or the friendship in order to limit conflict.",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Religious gatherings (temple/church/mosque, etc)",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Empathy",\n    "Creativity",\n    "Generosity",\n    "Genuineness",\n    "Gratitude",\n    "Inclusiveness",\n    "Passion",\n    "Purpose",\n    "Solitude",\n    "Sexuality"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Emotional availability, emotional intelligence, comfortable with have different opinions, healthy communication, honesty, integrity, not male centered, genuinely loving &amp; caring, supportive",\n  "friendship_values_dealbreakers": "Male centered, not emotionally available, easily triggered, not emotionally regulated, dishonest, doesn\u2019t know how to hold space for my emotions and is unwilling to try/learn",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Physical touch (hugging, holding hands)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Emotionally intelligent",\n  "wrapping_up_ideal_friend_words_word2": "Honest",\n  "wrapping_up_ideal_friend_words_word3": "Supportive",\n  "wrapping_up_what_want_receive": "A shared love amongst us for one another. Support no matter what and being willing to inconvenience (not in an unhealthy way) ourselves in the name of friendship",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "28-32",\n  "wrapping_up_open_to_multiple_matches": [\n    "No, I prefer to focus on one match at a time",\n    "No, I prefer to focus on one match at a time"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(66,106,replace('{\n  "tell_us_more_what_brings_you": "I recently moved to the area, and it''s been hard finding new friends!",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_gender_identity_details": "Cis woman",\n  "tell_us_more_about_yourself": "I am a very type A person, and I like to stay organized. I set goals for myself and value personal growth. I consider myself spiritual but not religious, and love to learn new things and explore myself and others more deeply. My friends and loved ones would say I''m the \"therapist friend,\" and I love to learn as much as possible about others. But, I can also be a chatty kathy as well. I have dry, sarcastic humor.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Health challenges",\n  "friendship_readiness_life_circumstances_details": "I have been looking for a best friend for a very long time, and want this to be a priority for myself..",\n  "friendship_readiness_showing_up": "It looks like calling and checking in several times a week, seeing each other in person at least 1-2 times weekly, and being able to hang out to do activities as well as just spending time together without a specific aim or goal. I value vulnerability and depth, and need consistency.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I have sought out friends who act in too much of a caregiving role with others and are overconfident in themselves, which has triggered old relationship wounds for me. I need someone who prioritizes me and wants to spend time together, and struggle with friends who meet up once in a blue moon and cancel often.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Rock climbing/adventure sports",\n    "Writing (journaling, poetry, books)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Astrology",\n    "Religious gatherings (temple/church/mosque, etc)",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_hobbies_details": "I am working on finding out what my hobbies are, and am open to doing this with others!",\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Empathy",\n    "Forgiveness",\n    "Genuineness",\n    "Growth",\n    "Trust",\n    "Community",\n    "Love",\n    "Resilience",\n    "Self-awareness",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I value friends who check in consistently",\n    "I need friends who can hold space for my emotions"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "I need consistency, emotional depth, and mutual caring.",\n  "friendship_values_dealbreakers": "I don''t like people who engage in a push-pull relationship pattern.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Authentic",\n  "wrapping_up_ideal_friend_words_word2": "Empathic",\n  "wrapping_up_ideal_friend_words_word3": "Humorous",\n  "wrapping_up_what_want_receive": "I would like to receive companionship, support, and someone to go through life with.",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "similar age to me (25-30ish)",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,107);
INSERT INTO assessment VALUES(68,109,replace('{\n  "tell_us_more_what_brings_you": "I\u2019m interested in making friends at my age. It seems challenging once I hit my 30s.",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I would say I\u2019m a goofy and outspoken girl. I\u2019m caring, introverted, and enjoy reading, going to sports events, playing pickleball and doing yoga.",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "I have an autoimmune disease that impacts my energy levels/fatigue",\n  "friendship_readiness_showing_up": "I like friends that I can meet up with and not feel pressure to see all the time. I like to do active things with my friends. I need friends who are low maintenance friends where we can pick up where we last left off",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "4",\n  "personality_social_style_ideal_hangout_2": "1",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Occasional meaningful texts",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Past challenges taught me that I do best with those who are direct but kind. I don\u2019t like people who center conversations around themselves all the time and don\u2019t ask about others.",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Sports (playing or watching)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Therapy/personal growth work",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Fun",\n    "Honesty",\n    "Passion"\n  ],\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "Being honest, not taking things too personally, enjoying doing things actively, balanced friendships, humor",\n  "friendship_values_dealbreakers": "Lying, being too whiny/clingy, expecting me to call/text all the time, mean girl energy",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Honest",\n  "wrapping_up_ideal_friend_words_word2": "Geniune",\n  "wrapping_up_ideal_friend_words_word3": "Funny",\n  "wrapping_up_what_want_receive": "Connections with others, female friends outside of my current friend groups",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "Similar age to me",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,129);
INSERT INTO assessment VALUES(69,110,replace('{\012  "tell_us_more_what_brings_you": "COVID has affected many of my friendships due to my risk factors. And really, can you ever have too much community?\n\n(re: next question-- i don''t identify with any of those labels as all of them leave disabled people behind AND won''t protect their community or themselves with masks.",\012  "tell_us_more_political_leanings": "Leftist",\012  "tell_us_more_gender_identity": "Non-binary",\012  "tell_us_more_about_yourself": "COVID CONSCIOUS\n\nI love plants, my dogs, and kids. I work with kids with autism as a career and love it more than almost anything. im disabled and bed bound with regularity. I mostly am into low energy hang outs but im also down to go thrifting or plant shopping or something of the like.",\012  "friendship_readiness_emotional_availability": "8",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": "Major career transition",\012  "friendship_readiness_life_circumstances_details": "I will be taking a new job soon which will affect my availability while I am learning to role (probably like 4-6 months) doesn''t mean i won''t have the capacity for new friends tho!",\012  "friendship_readiness_showing_up": "i love it when my friends lean on me. sometime showing up just means asking for your needs. going to the grocery store or doing laundry together  giving my friends a ride or other everyday things. i also need friends who mask at least around me and who consider my disabilities when making choices that affect me or our friendship.",\012  "personality_social_style_recharge_style": "5",\012  "personality_social_style_social_settings": "Share openly and engage actively with most people",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "3",\012  "personality_social_style_ideal_hangout_3": "4",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Phone calls",\012    "Primarily in-person hangouts"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Time and space before reconnecting"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Address it directly:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\012  "conflict_repair_friendship_lessons": "i have had friends who will slowly and intentionally peter out our friendship without telling me. i fucking hate that!!! no ghosting tf???\n\nnot sure but i may be more direct than people expect during conflict which especially with neurotypicals, can make things worse",\012  "hobbies_interests_activities_interests": [\012    "Visual arts (painting, drawing, photography)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Philosophy and deep conversations",\012    "Activism and social change",\012    "Therapy/personal growth work",\012    "Other"\012  ],\012  "hobbies_interests_activities_interests_other_text": "plants",\012  "hobbies_interests_hobbies_details": "",\012  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\012  "values_top_values": [\012    "Social Justice",\012    "Peace",\012    "Empathy",\012    "Forgiveness",\012    "Honesty",\012    "Inclusiveness",\012    "Non-conformity",\012    "Service"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Friends should challenge me to grow",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Consistency and reliability",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "covid cautious",\012  "friendship_values_dealbreakers": "not being willing to mask at a minimum around me, ableism/biggotry",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Once a week",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "warm",\012  "wrapping_up_ideal_friend_words_word2": "considerate",\012  "wrapping_up_ideal_friend_words_word3": "consistent",\012  "wrapping_up_what_want_receive": "mutual support and love",\012  "wrapping_up_gender_preference": "Non-binary",\012  "wrapping_up_age_preference": "no preference",\012  "wrapping_up_open_to_multiple_matches": [\012    "No, I prefer to focus on one match at a time",\012    "No, I prefer to focus on one match at a time"\012  ]\012}','\012',char(10)),1,145);
INSERT INTO assessment VALUES(70,111,replace('{\n  "tell_us_more_what_brings_you": "I recently moved to North Carolina in July of 2025 and I\u2019m looking to build community in this new city.",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "This is hard! Maybe I would be described as being on the more relaxed side? I tend to value a smaller amount of deep relationships. I think I\u2019m loyal and care about doing right by others and myself. I love exploring, learning, laughing.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "No",\n  "friendship_readiness_showing_up": "I think it looks like time and consistency. I think ultimately I\u2019m looking for people to spend time with.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "2",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Primarily in-person hangouts",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": "Acknowledgement of impact and sincere apology",\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "I think I\u2019ve had a history of being avoidant when I feel hurt or slighted, which typically manifests in me revoking my interest in people. However, I do recognize that this habit hurts me the most, so I\u2019m actively trying not to do that anymore.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Writing and reflection"\n  ],\n  "hobbies_interests_hobbies_details": "No",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Adventure",\n    "Peace",\n    "Family (chosen or biological)",\n    "Fun",\n    "Generosity",\n    "Genuineness",\n    "Growth",\n    "Community",\n    "Service",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Someone who is kind to others and cares about the people in their life.",\n  "friendship_values_dealbreakers": "Politically I need someone to the left. I wouldn\u2019t spend time with someone who I feel unsafe with or puts me in danger. Otherwise, I\u2019m open.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Physical touch (hugging, holding hands)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Vibrant",\n  "wrapping_up_ideal_friend_words_word2": "Accessible",\n  "wrapping_up_ideal_friend_words_word3": "Thoughtful",\n  "wrapping_up_what_want_receive": "Closeness. The absence of loneliness.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "No preference.",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,118);
INSERT INTO assessment VALUES(71,112,replace('{\n  "tell_us_more_what_brings_you": "i\u2019d like more friends with similar interests as me",\n  "tell_us_more_political_leanings": "Prefer not to say",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "i come off as quiet but i actually do love to yap!! slightly sarcastic sometimes tho",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "New parent/caregiving responsibilities",\n    "Other"\n  ],\n  "friendship_readiness_life_circumstances_other_text": "full time job",\n  "friendship_readiness_life_circumstances_details": "my job is pretty flexible but i usually need a week\u2019s notice before making plans!!",\n  "friendship_readiness_showing_up": "real conversations that don\u2019t feel one sided :) we can talk abt life or fairies as long as it\u2019s not forced",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": "Texting throughout the day",\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Prefer to avoid direct confrontation if possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Written communication (text, letter, etc)",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Set a boundary:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "i have a pattern of not reaching out that i am working on",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Music (playing, creating, deeply listening)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "It depends",\n  "values_top_values": [\n    "Beauty",\n    "Peace",\n    "Empathy",\n    "Creativity",\n    "Fun",\n    "Genuineness",\n    "Honesty",\n    "Loyalty",\n    "Purpose",\n    "Uniqueness"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value reliability and follow-through",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "honesty and similar sense of humor",\n  "friendship_values_dealbreakers": "trump supporter, pushing religious beliefs, and racist",\n  "friendship_values_connection_language": "Quality time (hangouts, phone calls, etc)",\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "funny",\n  "wrapping_up_ideal_friend_words_word2": "communicator",\n  "wrapping_up_ideal_friend_words_word3": "open",\n  "wrapping_up_what_want_receive": "someone to yap back and forth with",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "similar age (20) or 18-30",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(72,103,replace('{\n  "tell_us_more_what_brings_you": "I think I am friendly, but I''m kind of reserved and shy so I don''t try to make friends often. I just don''t really know how to start talking to some stranger without someone being the mutual friend.",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I don''t know if I have a lot to say or not much to say about myself. I think I am friendly and kind, but sometimes I can be monotone and/or sarcastic. I can be a little sensitive and emotional. I do not argue with anyone if I can help it.",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "It''s mostly a feeling of freedom and peace that I love to feel around my friends. That I can be myself and there''s no filter on my personality and I don''t feel as though we are a burden to each other. I love vulnerable, emotional conversations as much as I love fangirling convos, or silly girl convos. It''s really about being able to feel comfortable and safe with my friends.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "4",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "2",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "I don''t have to bottle up all of my emotions and get triggered and have it blow up and affect myself and everyone else. I''ve also learned that I am the type to have to step away from a situation and sit in my feelings and process those feelings to be able to explain WHY I felt the way I felt to not only my friends, but to myself. Sometimes, it''s a deeper issue I wasn''t aware of or actively dealing with, and I want to be able to sincerely apologize to anyone that may have been hurt or affected by whatever was said or a reaction of some sort.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Attending events (concerts, markets, etc)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "I honestly am willing to try almost any hobby and any interest because I''m a hobby gremlin. So I''m not opposed to other kinds of hobbies. :) I love learning about peoples favorite things and finding another thing to connect and bond over about said hobby/interest.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Health",\n    "Family (chosen or biological)",\n    "Fun",\n    "Generosity",\n    "Genuineness",\n    "Honesty",\n    "Inclusiveness",\n    "Passion",\n    "Patience",\n    "Self-awareness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friendship is about celebrating each other''s wins",\n    "I appreciate friends who respect my need for space"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Celebration of wins and joys",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Kindness. Inclusivity. Morals. Loves a joke. Understanding.",\n  "friendship_values_dealbreakers": "Clinginess. Jealousy of other friends/bonds. MAGA supporter. Overly negative (we can have bad days and complain about it, but every conversation doesn''t need to be like that). Silence on political events at ALL times (the world is tough and it is a PRIVILEGE to be able to say that it''s okay to take a break and enjoy a moment of silence in your brain- but to be completely silent at all times, that''s a deal breaker for me). The only way they have fun is drinking. I am a very casual drinker, minus on some occasions celebrating. So someone who heavily drinks to the point of blackouts super often is not ideal in a friendship for me.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Monthly",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Funny",\n  "wrapping_up_ideal_friend_words_word3": "Caring",\n  "wrapping_up_what_want_receive": "Lots of laughs, learning and girlhood vibes. Like even though things are tough, it will be okay type of energy because of bonds we form. :)",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "around the same age range as myself (29)",\n  "wrapping_up_open_to_multiple_matches": [\n    "I''m not sure",\n    "I''m not sure"\n  ]\n}','\n',char(10)),1,152);
INSERT INTO assessment VALUES(73,114,replace('{\012  "tell_us_more_what_brings_you": "Looking to make a few more meaningful, lifelong friendships. I''ve spent the last two years healing from a bit of friendship trauma. I absolutely adore the friends I''ve made along the way, but I think now I''m ready to open myself up a little more!",\012  "tell_us_more_political_leanings": "Leftist",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_gender_identity_details": "Cis woman",\012  "tell_us_more_about_yourself": "I like to say I''m an extroverted introvert. What I mean is I''m extremely shy and introverted when I meet people, but I literally thrive when I feel comfy and safe. I absolutely love having deep conversations about anything and everything. Nothing is too TMI. I''m someone who''s chronically online and loves to read. I have two black cats I adore. I love chill hangouts like going to the movies, coffee shops, or the house. But I also love going dancing and to a lounge. My flaws are that I''m an overthinker, a people pleaser, and someone who constantly needs to recharge my social battery.",\012  "friendship_readiness_emotional_availability": "9",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": [\012    "Major career transition",\012    "Other"\012  ],\012  "friendship_readiness_life_circumstances_other_text": "wants to find new hobbies",\012  "friendship_readiness_life_circumstances_details": "I''m introverted asl when I first meet people, so I know I''m gonna be awkward as FOOK.",\012  "friendship_readiness_showing_up": "Whew, this is a hard question lol. I want someone who is as considerate with my feelings as I try to be with others. I want a space where we each feel comfortable being vulnerable, but also where there''s no enablement of poor behavior.",\012  "personality_social_style_recharge_style": "2",\012  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\012  "personality_social_style_ideal_hangout_0": "2",\012  "personality_social_style_ideal_hangout_1": "1",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\012  "personality_social_style_communication_preference": [\012    "Voice notes",\012    "Primarily in-person hangouts"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Acknowledgement of impact and sincere apology",\012    "Time and space before reconnecting"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Address it directly:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "I struggle with communicating that I need space before an inevitable conversation about the conflict. I withdraw for multiple reasons. I don''t want to hurt the person''s feelings when I''m actively spiraling. I don''t want to interact because I''m angry. I want to understand my own feelings about it and find ways to communicate without going below the belt. It''s definitely a control issue because I''m the one who chooses when to discuss it, but it''s unfair because the person is left feeling hurt and is not given the same time to process everything.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Visual arts (painting, drawing, photography)",\012    "Music (playing, creating, deeply listening)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Cooking/Baking",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Book clubs or discussion groups",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Therapy/personal growth work",\012    "Video games (PC, PS, XBOX, Switch)",\012    "Other"\012  ],\012  "hobbies_interests_activities_interests_other_text": "Anime uWu",\012  "hobbies_interests_hobbies_details": "Currently open and trying to explore different hobbies. I''m trying not to be glued to my phone as much as I am.",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Harmony",\012    "Creativity",\012    "Nature",\012    "Health",\012    "Fun",\012    "Fulfillment",\012    "Honesty",\012    "Inclusiveness",\012    "Community",\012    "Solitude"\012  ],\012  "friendship_values_statements_resonate": [\012    "I appreciate friends who respect my need for space",\012    "Friends should accept me exactly as I am",\012    "Humor and laughter are essential to friendship"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "WOC, WOC, &amp; WOC.\n\nMust-haves for friendships are being understanding, genuine, and inclusive. Someone who''s funny/goofy asl and open to having deep conversations. Likes cats!! Not afraid to try something new",\012  "friendship_values_dealbreakers": "Someone who is male-centered or requires constant approval from their partner. Passive-aggressive. Unprovoked mean/rudeness. Kiss-ass. Taylor Swift fan.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)",\012    "Other forms of support (problem-solving, providing resources like money/meals)"\012  ],\012  "logistics_connection_frequency": "A few times a month",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Goofy",\012  "wrapping_up_ideal_friend_words_word2": "Genuine",\012  "wrapping_up_ideal_friend_words_word3": "Talkative",\012  "wrapping_up_what_want_receive": "Lifelong, meaningful friendship(s).",\012  "wrapping_up_gender_preference": "Woman",\012  "wrapping_up_age_preference": "Ooof, I''m aware I''m picky asl, but 27-30.",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,83);
INSERT INTO assessment VALUES(74,116,replace('{\012  "tell_us_more_what_brings_you": "I\u2019m finally a young adult!!! I\u2019ve moved out and I have a good job. So now I\u2019m trying to explore, go out, and try new things:) I\u2019m from Charlotte so I have connections with my lifelong friends but it wouldn\u2019t hurt to make some new ones!!!",\012  "tell_us_more_political_leanings": "Liberal",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I would describe myself as down to earth, funny and dependable. \nA true ambivert\ud83e\udd0f\ud83c\udffe\n\nI think family/friends would describe me as caring, easygoing and playful once you get to know me.",\012  "friendship_readiness_emotional_availability": "8",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\012  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\012  "friendship_readiness_life_circumstances": "N/A",\012  "friendship_readiness_life_circumstances_details": "Not that I know of",\012  "friendship_readiness_showing_up": "Showing up looks like quality time. I\u2019m always down for going out and trying a new activity together but also just sitting in the car and talking. Also checking in on each other. So I guess that would fall under energy and presence.",\012  "personality_social_style_recharge_style": "2",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "3",\012  "personality_social_style_ideal_hangout_2": "2",\012  "personality_social_style_ideal_hangout_3": "4",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Occasional meaningful texts",\012    "Primarily in-person hangouts"\012  ],\012  "personality_social_style_texting_style": "I prefer less frequent but more meaningful exchanges",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "Acknowledgement of impact and sincere apology",\012    "Time and space before reconnecting"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "I\u2019ve struggled with is consistency in communication. I\u2019ve become the low maintenance friend (which doesn\u2019t bother me) with all my friends. They know it\u2019s love even though we don\u2019t communicate 24/7. I lost (more like we just drifted apart) a friend like that because she didn\u2019t prefer relationships like that. So I want to try and be more consistent with my new friendships",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Yoga/Pilates",\012    "Music (playing, creating, deeply listening)",\012    "Fashion/Styling",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Podcasts and documentaries",\012    "Meditation/mindfulness",\012    "Astrology",\012    "Nature connection and grounding"\012  ],\012  "hobbies_interests_hobbies_details": "I also love makeup!!",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Social Justice",\012    "Peace",\012    "Creativity",\012    "Nature",\012    "Family (chosen or biological)",\012    "Genuineness",\012    "Trust",\012    "Love",\012    "Passion",\012    "Self-expression"\012  ],\012  "friendship_values_statements_resonate": [\012    "I appreciate friends who respect my need for space",\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Mutual support during hard times",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "Must be respectful to me and others and even strangers.\nLoyalty and Supportive (we have to have each others back)\nAnd to be able to relate to one another \nOpen minded",\012  "friendship_values_dealbreakers": "Things feeling one sided or no effort being put in\nNegative/ Dishonest/ like being in drama",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Physical touch (hugging, holding hands)",\012    "Gifts (items that remind them of you)"\012  ],\012  "logistics_connection_frequency": "A few times a month",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "Genuine",\012  "wrapping_up_ideal_friend_words_word2": "Funny",\012  "wrapping_up_ideal_friend_words_word3": "Positive Energy",\012  "wrapping_up_what_want_receive": "Genuine Friends ( one or even a group ) who are down to laugh, hang out, vent and just enjoy life",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "Around my age (21-25)",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(75,117,replace('{\n  "tell_us_more_what_brings_you": "I turned 30 last year and I find that I don\u2019t have any close friends anymore. After becoming a mom and wife it felt like I lost my identity for a few years. It feel like I have to relearn myself and work on making new friends has been a challenge.",\n  "tell_us_more_political_leanings": "Prefer not to say",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I would describe myself as loyal and very head strong. My circle is small and I go to bat for my friends. I am extremely reliable and helpful in most situations",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances_details": "No",\n  "friendship_readiness_showing_up": "I feel like in the past I always reached out to friends and it\u2019s never return to me. A friend to me is someone that reaches out to you with the good bad and ugly. As an adult our life\u2019s can get chaotic and it can be hard to make plans but just taking the initiative is enough for me.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Texting throughout the day"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "In the past it feels like because my circle is small some disagreements can feel personal.  It feels like I\u2019m the only one keeping things friendships alive at some points",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "I love to read books and audiobooks. About 2-3 a week. I love food and use to be a professional pastry chef. Either going out and/or cooking at home.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Adventure",\n    "Assertiveness",\n    "Fun",\n    "Generosity",\n    "Honesty",\n    "Passion",\n    "Patience",\n    "Responsibility",\n    "Self-awareness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Celebration of wins and joys",\n    "Non-judgment and acceptance",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "I\u2019m really go with the flow. But my biggest pet peeves is lateness and communication",\n  "friendship_values_dealbreakers": "Lying to myself or other friends/families.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Trustworthy",\n  "wrapping_up_ideal_friend_words_word2": "Supportive",\n  "wrapping_up_ideal_friend_words_word3": "Entertaining",\n  "wrapping_up_what_want_receive": "Connect with new people and be more aware in my community",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "No preference",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,129);
INSERT INTO assessment VALUES(76,118,replace('{\n  "tell_us_more_what_brings_you": "I moved to Charlotte in July 2025, and I am acknowledging that making friends as an adult is so stinking hard",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Moderate"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I am a funny and outgoing introvert, who likes to spend time trying new restaurants, doing crafts, cooking, and baking, and hopefully taking a cake decorating class soon",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Showing up in a friendship to me means consistent communication and check-in, and active effort to put in time and energy",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Video calls"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I am one to give many chances, and let others guide the friendship without really letting my voice be headd",\n  "hobbies_interests_activities_interests": [\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Therapy/personal growth work",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Social Justice",\n    "Empathy",\n    "Trust",\n    "Love",\n    "Passion",\n    "Patience",\n    "Purpose",\n    "Resilience",\n    "Self-awareness",\n    "Stability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I need friends who can hold space for my emotions",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "A big nonnegotiable for me is lacking, empathy, and social awareness. Being close minded.",\n  "friendship_values_dealbreakers": "Someone who is inconsistent, lacks structure, and boundaries, and is super last minute",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Caring",\n  "wrapping_up_ideal_friend_words_word3": "Funny",\n  "wrapping_up_what_want_receive": "I would like to receive a sense of belonging and acceptance",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "No preference",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,142);
INSERT INTO assessment VALUES(77,119,replace('{\n  "tell_us_more_what_brings_you": "Recently I\u2019ve found myself wanting to connect with like minded individuals. I usually stay to myself but I would like to have a circle of friends to just enjoy a nice lunch with.",\n  "tell_us_more_political_leanings": "Prefer not to say",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I\u2019m observant, bubbly and kind. My family would say I\u2019m dependable and hold others accountable for their actions. Goal oriented and a loving mother.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "New parent/caregiving responsibilities",\n  "friendship_readiness_life_circumstances_details": "I am a single mother so while I have free time, it has to be planned accordingly. Also I am not against having mommy friends. Always down for a playdate!",\n  "friendship_readiness_showing_up": "Someone giving consistent effort to communicate. I understand life is hectic so meet ups are not priority number one.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "I\u2019ve learned I can be blunt and brutally honest. I understand some people do not like this. I also have the tendency to drop someone after addressing a situation more than once.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "I\u2019m open to learning and exploring new hobbies",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Ambition",\n    "Peace",\n    "Empathy",\n    "Fun",\n    "Growth",\n    "Honesty",\n    "Trust",\n    "Inclusiveness",\n    "Loyalty",\n    "Uniqueness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I value friends who check in consistently",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Non-judgment and acceptance",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "I accept a person for who they are but if you can\u2019t be flexible when it comes to my schedule surrounding my child, it will not work. Also I work third shift so there will be days I need to sleep in to recharge, patience is a necessity.",\n  "friendship_values_dealbreakers": "Repeatedly canceling plans with no good reasoning. Inconsistency. Inability to handle criticism.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Humble",\n  "wrapping_up_ideal_friend_words_word2": "Kind",\n  "wrapping_up_ideal_friend_words_word3": "Flexible",\n  "wrapping_up_what_want_receive": "A friend to share life experiences with and travel",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "Similar age to me, open to any age range as well",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(78,120,replace('{\012  "tell_us_more_what_brings_you": "I am newly single and a mom of two kids. Every single one of my friends is married or in a serious relationship, and I would like to find some single friends, particularly single mom friends. I\u2019d like to have people who understand what I\u2019m going through and who will have a similar lifestyle as me.",\012  "tell_us_more_political_leanings": "Liberal",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I am an introvert, but open up a lot around people I feel comfortable with. I enjoy going out and doing new things, and I also love to stay at home with a good book. I love to laugh. I am passionate and silly and caring.",\012  "friendship_readiness_emotional_availability": "9",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": [\012    "Major career transition",\012    "Ending a significant relationship",\012    "Major life transition (marriage, divorce, etc)"\012  ],\012  "friendship_readiness_life_circumstances_details": "I have limited time to invest in friendships, but when I am able to invest, I am able to be fully present. I have two young children who are now with their dad every other weekend, and during those times I am able to be fully present investing in myself and new friendships. But when the kids are with me, they are my first priority.",\012  "friendship_readiness_showing_up": "Texting to check in and remembering important things going on in their life that I can ask about. I like having deep conversations, but also connecting on silly things or things we have in common, so I can do that through text when I\u2019m not able to be in person.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\012  "personality_social_style_communication_preference": [\012    "Texting throughout the day",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Acknowledgement of impact and sincere apology"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "2",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "I tend to feel closer to others than they feel to me. Although I prefer regular texting communication, I can still feel close to someone if life happens and we don\u2019t talk for a few months, and then I\u2019ll reconnect right where we left off. But friends I\u2019ve had in the past have moved on to other friendships when there has been a communication lull.",\012  "hobbies_interests_activities_interests": [\012    "Yoga/Pilates",\012    "Book clubs or discussion groups",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Therapy/personal growth work",\012    "Energy work/holistic practices"\012  ],\012  "hobbies_interests_hobbies_details": "It\u2019s been helpful in the past when a new friend is also a reader because it\u2019s a quick topic to connect on to break the ice",\012  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\012  "values_top_values": [\012    "Social Justice",\012    "Empathy",\012    "Fun",\012    "Trust",\012    "Vulnerability"\012  ],\012  "friendship_values_statements_resonate": [\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me",\012    "I value friends who share my worldview and values"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Consistency and reliability",\012    "Genuineness",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "I am liberal, LGBT affirming, anti ICE, etc. and I think I\u2019d have a hard time being friends with someone who doesn\u2019t hold similar views. \nI also need a friend who understands that life is challenging right now with a recent divorce and being a newly single mom to two kids. Ideally my friend would check in on me from time to time to see how I\u2019m doing and be flexible and want to hang out during the times when I am available.",\012  "friendship_values_dealbreakers": "Someone who is not able to maintain a relationship through the ebbs and flows of friendship. Someone who has conservative views.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)",\012    "Other forms of support (problem-solving, providing resources like money/meals)"\012  ],\012  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "Initiative (not sure the right word, but someone who initiates connection)",\012  "wrapping_up_ideal_friend_words_word2": "Fun/adventurous",\012  "wrapping_up_ideal_friend_words_word3": "Vulnerable",\012  "wrapping_up_what_want_receive": "I would like a support system of one or two single mom friends who really understand my new life, and are also game for going to singles events and other things that our married mom friends aren\u2019t going to go to with us. I need an emotional support friend as I navigate this new life, and I\u2019d love to be that for someone else as well!",\012  "wrapping_up_gender_preference": "Woman",\012  "wrapping_up_age_preference": "Similar age to me",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(79,124,replace('{\012  "tell_us_more_what_brings_you": "My therapist wanted me to diversify my friend groups, and I realized I haven''t exactly had a lot of friends to match my energy and interests.",\012  "tell_us_more_political_leanings": [\012    "Liberal",\012    "Leftist"\012  ],\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I''m pretty chronically online and I have an awkward sense of humor, but I''m also very dynamic in my emotions whenever I wanna tell a story or captivate people''s interests. I try my best to consider people''s feelings and attempt to listen what people are into to the best of my ability, but I try my best to let people know if I can''t exactly get into things right now.\n\nI really like talking about niche interests such as Dragon Raja, Myth of the Machine, and a select others. But I also like to draw my favorite characters and occasionally write when I''m not being hit with the need to make it really good.",\012  "friendship_readiness_emotional_availability": "7",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\012  "friendship_readiness_personal_work": "I am aware of patterns but haven''t worked through them yet",\012  "friendship_readiness_life_circumstances": "Other",\012  "friendship_readiness_life_circumstances_other_text": "Having to end a friendship and deal with friends being really disrespectful recently",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Being able to come when I''m feeling very emotionally exhausted or hurt when needed. Sometimes, being able to hang out, whether physically or through text. Able to listen to my interests with a good amount of emotional investment without constantly turning it back to themselves or implicitly or explicitly dismissing said interests. Being able to match my energy.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Share openly and engage actively with most people",\012  "personality_social_style_ideal_hangout_0": "3",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\012  "personality_social_style_communication_preference": [\012    "Phone calls",\012    "Texting throughout the day"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Prefer to avoid direct confrontation if possible",\012  "conflict_repair_repair_looks_like": [\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\012  "conflict_repair_feedback_comfort": "2",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "I have a hard time trying to communicate how I''m feeling because I feel like I''m being hypocritical or feeling unjustified in having issues with another person. Most times I try to think on the logistics of how that person is feeling, and try to internalize my hurt and try to somehow move past that by \"processing it,\" when in reality I''m just bottling things up.\n\nI also have a hard time trying to make myself the funniest or more intriguing person in the room, so I often overextend or go to extremities to make sure that I''m going to be a consistent presence and high priority in people''s lives.",\012  "hobbies_interests_activities_interests": [\012    "Writing (journaling, poetry, books)",\012    "Visual arts (painting, drawing, photography)",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Attending events (concerts, markets, etc)",\012    "Video games (PC, PS, XBOX, Switch)"\012  ],\012  "hobbies_interests_hobbies_details": "I''m heavily invested in talking about Dragon Raja, specifically the main character named Lu Mingfei. Most times, I really like rambling on about this character and like drawing things in relation to him. A lot of my conversations tend to be fandom-related, but I can easily just try to make lighthearted conversations on other things.",\012  "hobbies_interests_doing_vs_being": "It depends",\012  "values_top_values": [\012    "Social Justice",\012    "Empathy",\012    "Forgiveness",\012    "Genuineness",\012    "Trust",\012    "Inclusiveness",\012    "Love",\012    "Passion",\012    "Stability",\012    "Vulnerability"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should accept me exactly as I am",\012    "I need friends who can hold space for my emotions",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Non-judgment and acceptance",\012    "Genuineness"\012  ],\012  "friendship_values_non_negotiables": "Common interests would be most preferred, so we can have something to go off of. Someone who doesn''t immediately ram or sidetrack my conversation back to them, when I''m in the middle of talking about stuff that I like or am interested in.",\012  "friendship_values_dealbreakers": "Mansplaining, or acting like I am less experienced in something than I actually am. Someone who keeps talking about themselves more often than I am able to, and keeps trying to switch or derail the conversation about themselves personally. Someone who keeps acting like they''re very experienced and very important for certain topics to the point of a superiority complex.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Multiple times per week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Compassionate",\012  "wrapping_up_ideal_friend_words_word2": "Supportive",\012  "wrapping_up_ideal_friend_words_word3": "Like-minded",\012  "wrapping_up_what_want_receive": "Emotional support, someone to match my energy in needs and interests. Being able to feel like I''m not alone around people my age.",\012  "wrapping_up_gender_preference": "Woman",\012  "wrapping_up_age_preference": "Similar age to me is preferred",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,145);
INSERT INTO assessment VALUES(80,107,replace('{\012  "tell_us_more_what_brings_you": "I am recently diagnosis autistic level one, I am looking to connect with other people in a meaningful way and hopefully develop a relationship that lasts the rest of my life with one to two people. I have not had many friends in my life and now that I''ve finally gain the courage to leave isolation, I am hoping that the start of this journey is gentle to me since I have a hard time in social settings especially if it''s not one on one.",\012  "tell_us_more_political_leanings": [\012    "Liberal",\012    "Moderate"\012  ],\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I think most people would describe me as serious because they do not know me. I do not really have friends, I have people that I support through life experiences - I know quite a bit about them but they do not know much about me.\n\nPart of this is my fault, I am afraid to open up because I worry that I will be judged since I do not think the same and neurotypical people. I am extremely interested in a few things and find little interest in many things because I''d rather engage in one or two activities. \n\nBut once someone gets to know me, I think they will see that I am:\nSensitive\nSocially Timid\nIntellectually Confident\nOrganized\nEmpathetic\nCompassionate\nInventive or Creative\nConsiderate/Mindful\nLogical \n\nI like video games, frogs, blankets, hiking, boba, cookies, candles, philosophy, reading (romance, fantasy, educational) and any shade of green. I''ve been in an abusive relationship before and have experienced sexual trauma so I would like to be match with someone who is empathetic and",\012  "friendship_readiness_emotional_availability": "6",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": "Other",\012  "friendship_readiness_life_circumstances_other_text": "As I mentioned before I am recently diagnosed level 1 autism and that has been a big thing for me to deal with. I feel like it has explained why people did not like me and do not like me now. I am a little worried about what this means for my future relationships, but I''m not so afraid that I won''t try to have any.",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Vulnerability and consistency. \nVulnerability - I would like to be able to tell this person anything and everything I am thinking in a space that is safe and where I won''t be judged. I need this to be reciprocated to some degree, I want this to be an exchange and experience of who we are individually and together. \n\nConsistency - When I say consistency I do not mean we have to text everyday, although I would be happy to do so as long as I can be who I am and you will be who you are. I want to speak at least 1-3 times a week, and I''d like to be able to connect in person at least once monthly to hang out. I do not have a particular need on what hanging out looks like, I just ask it not to involve too many people (5+ people) socially because I am easily overstimulated and would need a lot of trust between my friend first before I do so.\n\nNote: Often, I end up in spaces where either the other person will tell me everything about them but not care about anything I want to share, or I''ll be",\012  "personality_social_style_recharge_style": "2",\012  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\012  "personality_social_style_ideal_hangout_0": "4",\012  "personality_social_style_ideal_hangout_1": "3",\012  "personality_social_style_ideal_hangout_2": "1",\012  "personality_social_style_ideal_hangout_3": "2",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Primarily in-person hangouts",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\012  "conflict_repair_repair_looks_like": "Other",\012  "conflict_repair_repair_looks_like_other_text": "This question feels loaded and unfair to respond to. Repair to me looks like all of these things depending on the severity of what the conflict is. I consistently prefer someone to acknowledge the impact/experience I had and apologize if they truly did not want to experience that. I would then proceed to have a direct conversation on how we can make sure together we avoid that type of conflict. I then would prefer to spend time with the person in a meaningful way but it does not have to be immediately (although I prefer it to be within 1-2 days of the conflict resolution).",\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "5",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "This question makes me sad honestly...\nI have not had many friendships in my life, and the last friendship I did have was when I was 15 years old. After that I did not have friendships, but romantic relationships so I will speak on what those taught me.\n\nWhat I''ve noticed about myself is that I NEED safety and the way safety is created is important to me. I do not like the absence of vulnerability. I want to feel connected and I cannot unless we are both vulnerable and honest. \n\nI have also learned that I am too rigid in my approaches and can be dismissive when I think that someone else''s experience is coming from a place of stupidity. Stupidity is defined to me as choosing the same thing over and over and expecting a different response or willing fully choosing to be ignorant.  I have worked on this by taking a coaching class that I was intending to actualize a coaching certification from. Instead, it allowed me to become aware of how I can hold space, remain curious and kind without",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Yoga/Pilates",\012    "Running/Cycling",\012    "Writing (journaling, poetry, books)",\012    "Visual arts (painting, drawing, photography)",\012    "Music (playing, creating, deeply listening)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Fashion/Styling",\012    "Volunteering/advocacy",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Writing and reflection",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Astrology",\012    "Therapy/personal growth work",\012    "Nature connection and grounding",\012    "Energy work/holistic practices",\012    "Video games (PC, PS, XBOX, Switch)"\012  ],\012  "hobbies_interests_hobbies_details": "",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Peace",\012    "Empathy",\012    "Spirituality",\012    "Growth",\012    "Honesty",\012    "Trust",\012    "Love",\012    "Self-awareness",\012    "Self-expression",\012    "Vulnerability"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should challenge me to grow",\012    "I value reliability and follow-through",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "Open-Mindedness\nSelf-Awareness\nWillingness\nValuing Choice/Autonomy\nAdaptability\nHonesty\nTrust\nCare\nGrace\nKindness\nRespect\nEmpathy\nSafety\nGrowth Mindset",\012  "friendship_values_dealbreakers": "Inconsistency\nLack of Personal Ambition\nDoes not value Intellect\nDoes not value Autonomy\nLacks curiosity\nLacks empathy\nUnmotivated\nComplacency\nMale Centering\nUnforgiving\nUnwilling to Change\nLack of Boundaries (none at all - I am fine if they are working on it, so am I)\nLack of Consideration\nLack of Self Awareness.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Physical touch (hugging, holding hands)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Once a week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Intellectual",\012  "wrapping_up_ideal_friend_words_word2": "Considerate",\012  "wrapping_up_ideal_friend_words_word3": "Curious",\012  "wrapping_up_what_want_receive": "Joy, support, love, peace, encouragement, and pleasure.\n\nI want to feel the authentic and most beautiful aspects of human connection with another person. I am aware that situations will rise and those aspects I named above will appear to be \"missing\" for brief moments, but I want to know that is a flicker of a moment and not a consistent reality. I am exhausted of feeling isolated and hopeless that I cannot connect with another person genuinely. I want to support someone, I want to cheer them on, I want to celebrate, I want to cry, I want to hug, I want to love. I want to receive all those things too. I am not afraid of the conflict or of love; I am afraid that conflict is all that will exist when I seek connection with another person because I am different (neurodivergent).",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "I would like someone who is close to my age. I am 28 years old and I prefer they either be 5 years old or 5 years younger than me as the maximum.",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),1,106);
INSERT INTO assessment VALUES(81,125,replace('{\n  "tell_us_more_what_brings_you": "Saw this pop up on instagram and thought it would be fun to attend !! Currently a university student and love going on little side quests trying new things",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Prefer not to say"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "Spontaneous, introverted until I get a bit comfortable, and very honest with a dry sense of humor. I love music, roller skating, and going on walks !!",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Communication and consistency !!",\n  "personality_social_style_recharge_style": "4",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Video calls",\n    "Voice notes"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Written communication (text, letter, etc)",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "I\u2019ve noticed that while others prefer to keep things to themselves Im always the type to confront the issue upfront and that can tend to upset others.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Sports (playing or watching)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Therapy/personal growth work",\n    "Video games (PC, PS, XBOX, Switch)",\n    "Other"\n  ],\n  "hobbies_interests_activities_interests_other_text": "Roller skating",\n  "hobbies_interests_hobbies_details": "Always open to try new things!!",\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Career",\n    "Creativity",\n    "Trust",\n    "Self-awareness",\n    "Work Ethic"\n  ],\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "Honesty, consistency, and priorities seem to be straight- I find it very important to surround myself with people I can see growth in",\n  "friendship_values_dealbreakers": "If they don\u2019t like consistency in communication",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Consistent",\n  "wrapping_up_ideal_friend_words_word2": "Fun !!",\n  "wrapping_up_ideal_friend_words_word3": "Honest",\n  "wrapping_up_what_want_receive": "People who reciprocate the vibes given !!",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "&lt;24",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,151);
INSERT INTO assessment VALUES(82,126,replace('{\n  "tell_us_more_what_brings_you": "I would love to finder deeper friendships in Charlotte. I am a transplant.",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I love to be outdoors, crafting, reading, shopping, or traveling :). I am a girls girl.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Showing up in friendship to me means being there for someone through the highs and the lows because you care about them and want them to be happy.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "4",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "Showing up for your friends matters a lot, even if you are going through conflicts. Putting the work into friendships is worth it.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Sports (playing or watching)",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_hobbies_details": "happy to learn anything new :)",\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Ambition",\n    "Empathy",\n    "Forgiveness",\n    "Genuineness",\n    "Trust",\n    "Inclusiveness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I value reliability and follow-through",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Consistency and reliability",\n    "Genuineness"\n  ],\n  "friendship_values_non_negotiables": "Being genuine and kind-hearted",\n  "friendship_values_dealbreakers": "NA",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Compassionate",\n  "wrapping_up_what_want_receive": "A safe place to meet and form impactful friendships",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "Similar age to me - mid 20s",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(83,128,replace('{\012  "tell_us_more_what_brings_you": "I\u2019ve been focused on my own growth and responsibilities, but in the process I realized I don\u2019t really have the kind of community I want around me right now. So I\u2019m trying to be more intentional about meeting new people, building genuine connections, and surrounding myself with energy that feels supportive and positive.",\012  "tell_us_more_political_leanings": "Liberal",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I\u2019d describe myself as creative, open-minded, and expressive. I love fashion and writing because they let me show different sides of who I am whether that\u2019s through my style or my thoughts. I\u2019m always exploring new ideas and not afraid to try new things.\nMy friends would say I\u2019m creative, supportive, and easy to talk to, with a unique sense of style and a fresh perspective.",\012  "friendship_readiness_emotional_availability": "8",\012  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": "N/A",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Right now, showing up in a friendship means being intentional and consistent. Checking in, making time for each other, and actually being present not just surface-level. It\u2019s about listening, supporting each other, and following through on what you say you\u2019ll do.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\012  "personality_social_style_communication_preference": [\012    "Primarily in-person hangouts",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\012  "conflict_repair_repair_looks_like": [\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me that I tend to withdraw when I\u2019m overwhelmed instead of communicating, and that can create distance even when I care about the person. I\u2019ve also realized I sometimes give a lot without always expressing my own needs clearly.\n\nIt\u2019s pushed me to be more honest, more consistent, and more intentional about the kind of friendships I want.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Running/Cycling",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Sports (playing or watching)",\012    "Writing (journaling, poetry, books)",\012    "Visual arts (painting, drawing, photography)",\012    "Music (playing, creating, deeply listening)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Cooking/Baking",\012    "Fashion/Styling",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Learning new skills",\012    "Writing and reflection",\012    "Meditation/mindfulness",\012    "Tarot/oracle cards",\012    "Nature connection and grounding",\012    "Video games (PC, PS, XBOX, Switch)"\012  ],\012  "hobbies_interests_hobbies_details": "",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Empathy",\012    "Creativity",\012    "Family (chosen or biological)",\012    "Genuineness",\012    "Growth",\012    "Trust",\012    "Loyalty",\012    "Love",\012    "Passion",\012    "Self-expression"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should challenge me to grow",\012    "Friends should accept me exactly as I am",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "My non-negotiables are honesty, consistency, and mutual respect. I need friendships where there\u2019s clear communication, not guessing games, and where effort goes both ways.",\012  "friendship_values_dealbreakers": "I can\u2019t maintain friendships where there\u2019s disrespect, lack of accountability, or patterns of one-sided effort. If there\u2019s no mutual respect for boundaries, or if things turn into unnecessary drama or negativity, that\u2019s something I try to step away from.",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "I am open",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "Creative",\012  "wrapping_up_ideal_friend_words_word2": "Authentic",\012  "wrapping_up_ideal_friend_words_word3": "Emotionally mature",\012  "wrapping_up_what_want_receive": "I\u2019d like to receive consistency, honesty, and genuine effort in friendship. People who communicate openly, check in without it feeling forced, and show up in both the good times and the challenging ones.",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "No preference",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(84,129,replace('{\n  "tell_us_more_what_brings_you": "I''m relatively new to town and I''m looking to build new friendships.",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I''m someone that genuinely cares for others. I''m optimistic, curious, and enjoy the simple things in life-a good meal, nature, laughing, and good conversations. I''m reliable, opinionated,and sometimes goofy. I love exploring new spots in town as much as staying in and watching a good movie. I find joy in little things!",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": [\n    "Recent/upcoming move",\n    "Major life transition (marriage, divorce, etc)"\n  ],\n  "friendship_readiness_life_circumstances_details": "I recently got married, so I do have certain responsibilities and priorities in regards to my building a new home and hanging out with my husband sometimes.",\n  "friendship_readiness_showing_up": "Showing up means being open to talk and be candid. It means sharing lifes ups and downs, but also having fun. Being consistent, being present and making an effort go a long way. Say what you mean and mean what you say.",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Occasional meaningful texts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Past friendships have taught me that it''s important to set boundaries and not overextend yourself. Everything needs to be reciprocal. Although life happens, accountability is important.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Nature connection and grounding",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "I like nature walks and spin classes. I also like crafting-painting, drawing and collaging. I also really enjoy cooking.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Empathy",\n    "Nature",\n    "Health",\n    "Family (chosen or biological)",\n    "Fun",\n    "Generosity",\n    "Genuineness",\n    "Gratitude",\n    "Honesty",\n    "Self-awareness"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should challenge me to grow",\n    "Mutual effort and reciprocity matters to me",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Genuineness",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "Being on time and being honest.",\n  "friendship_values_dealbreakers": "Too much sarcasm, someone that just wants to party, someone that is not empathetic.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Optimistic",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Fun",\n  "wrapping_up_what_want_receive": "Reciprocity, honesty, and new shared experiences",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "At least 28 years old",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),1,109);
