INSERT INTO assessment VALUES(105,159,replace('{\012  "tell_us_more_what_brings_you": "im originally from the coastal part North Carolina but I\u2019ve spent the better part of the last two years working at disney world! I just moved to Charlotte and am looking for queer community:)",\012  "tell_us_more_political_leanings": "Leftist",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "im very social! I\u2019ve never met a stranger. I love to go on spontaneous adventures even if it\u2019s just to do little things get never done before. I am obsessed with accessorizing. funky accessories have my heart! I\u2019m known for my crazy earrings. A regular at my old job would always come in and ask what earrings I had on that day. I love going on but am also an enjoyer of cozy nights in. I\u2019m trying to get into cooking/baking but it is not going very well\ud83d\ude05.",\012  "friendship_readiness_emotional_availability": "10",\012  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\012  "friendship_readiness_life_circumstances": "N/A",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Friendship as an adult I feel is realizing that we all have super busy lives, but just taking time out of your busy schedule to make sure your friends are seen is so important to me! Even if it\u2019s just a simple text!",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "2",\012  "personality_social_style_ideal_hangout_1": "1",\012  "personality_social_style_ideal_hangout_2": "3",\012  "personality_social_style_ideal_hangout_3": "4",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\012  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\012  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me that talking it out is necessary to keep a strong friendship. I used to never say anything when I was upset about something but that led to everything building up and spilling out at once. I\u2019m now so much better at conflict resolution and having those tough conversations.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Writing (journaling, poetry, books)",\012    "Visual arts (painting, drawing, photography)",\012    "Music (playing, creating, deeply listening)",\012    "Cooking/Baking",\012    "Fashion/Styling",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Podcasts and documentaries",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Writing and reflection",\012    "Activism and social change",\012    "Therapy/personal growth work",\012    "Nature connection and grounding"\012  ],\012  "hobbies_interests_hobbies_details": "",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Social Justice",\012    "Empathy",\012    "Family (chosen or biological)",\012    "Genuineness",\012    "Trust",\012    "Inclusiveness",\012    "Community",\012    "Thrift",\012    "Work Ethic",\012    "Sexuality"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Friendship is about celebrating each other''s wins",\012    "I value friends who check in consistently"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Consistency and reliability",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "My biggest thing is trust! If I can\u2019t trust you I can\u2019t have any sort of meaningful relationship with you.",\012  "friendship_values_dealbreakers": "- conservative \n- not respecting time\n- unable to apologize",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Emotional Support (showing up in hard times, being a listening ear)",\012    "Other forms of support (problem-solving, providing resources like money/meals)"\012  ],\012  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "spontaneous",\012  "wrapping_up_ideal_friend_words_word2": "honestly",\012  "wrapping_up_ideal_friend_words_word3": "funny",\012  "wrapping_up_what_want_receive": "Honestly I just want to meet people who are genuine and can laugh at silly things until we can\u2019t breathe but also show up during hard times!",\012  "wrapping_up_gender_preference": [\012    "Woman",\012    "Non-binary"\012  ],\012  "wrapping_up_age_preference": "similar age to me preferred but im not picky!",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(106,162,replace('{\n  "tell_us_more_what_brings_you": "I''m a stay at home mom who would love new community. My husband and I moved to Charlotte in 2024 right before I gave birth so it would be nice to meet new friends.",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Moderate"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I would describe myself as a loyal friend who is always down to support you. Also, I enjoy being the friend that you can text all your rambling thoughts to. I''m definitely the friend that will hold you accountable to your silliness but defend you ferociously in public.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "New parent/caregiving responsibilities",\n  "friendship_readiness_life_circumstances_details": "My biggest priority in life is my child. So, my availability definitely depends on his schedule however I have the time and ability to sustain a new friendship at the moment.",\n  "friendship_readiness_showing_up": "Oooh I love this question. It means texting and being able to hang out regularly. But also, being invested in the others life, asking the follow up questions, knowing the key players in the others life.",\n  "personality_social_style_recharge_style": "5",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "I was ill prepared to deal with friendship loss. Since I generally have such all in friendships, the absence of a relationship is a much bigger deal than I expected",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Activism",\n    "Adventure",\n    "Career",\n    "Social Justice",\n    "Family (chosen or biological)",\n    "Genuineness",\n    "Community",\n    "Intuition",\n    "Loyalty",\n    "Love"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friendship is about celebrating each other''s wins",\n    "I value friends who check in consistently"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Loyal. Kindness. Reciprocity.",\n  "friendship_values_dealbreakers": "Someone who doesn''t have your back. Trump voters.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Loyal",\n  "wrapping_up_ideal_friend_words_word2": "Funny",\n  "wrapping_up_ideal_friend_words_word3": "Connection",\n  "wrapping_up_what_want_receive": "Just a person who I feel like is my person.",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "Similar to me",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(107,161,replace('{\012  "tell_us_more_what_brings_you": "I found three of cups through Julia collaborating with y''all to host yoga classes. I\u2019ve been in Charlotte for the past 3 years, attending UNCC but I still have yet to find my community or close friends.",\012  "tell_us_more_political_leanings": [\012    "Moderate",\012    "Apolitical"\012  ],\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_about_yourself": "I would describe myself as introverted but once you get to know me I am a great person to be around. I\u2019m funny, caring, and optimistic. I respect everyone as long as you respect me and others. I\u2019m a huge empath so I do feel things deeply. If my family or friends were to describe me they would say that I\u2019m creative, free spirited, and easygoing.",\012  "friendship_readiness_emotional_availability": "7",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\012  "friendship_readiness_personal_work": "I don''t think I have significant friendship wounds",\012  "friendship_readiness_life_circumstances": "N/A",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Showing up for a friend to me is being just a text or call away when something good or bad happens. I really want to have a friendship where we help each other to our best ability.",\012  "personality_social_style_recharge_style": "2",\012  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\012  "personality_social_style_communication_preference": [\012    "Voice notes",\012    "Mix of everything/I''m flexible"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\012  "conflict_repair_repair_looks_like": [\012    "Quality time together to reconnect",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\012  "conflict_repair_friendship_lessons": "Past friendship challenges have taught me to stand up for myself, set boundaries, and be consistent.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Yoga/Pilates",\012    "Running/Cycling",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Music (playing, creating, deeply listening)",\012    "Crafting (pottery, knitting, DIY, etc)",\012    "Cooking/Baking",\012    "Hosting gatherings (dinner parties, game nights)",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Activism and social change",\012    "Meditation/mindfulness",\012    "Nature connection and grounding",\012    "Energy work/holistic practices",\012    "Medicinal herbs/substances"\012  ],\012  "hobbies_interests_hobbies_details": "I also love shopping and doomscrolling on Pinterest lol. I also want to get in boiler rooms for dj-ing.",\012  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\012  "values_top_values": [\012    "Career",\012    "Peace",\012    "Nature",\012    "Health",\012    "Genuineness",\012    "Gratitude",\012    "Growth",\012    "Trust",\012    "Community",\012    "Passion"\012  ],\012  "friendship_values_statements_resonate": [\012    "Friends should be able to have difficult conversations",\012    "Friendship is about celebrating each other''s wins",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "My non-negotiables are \n- respecting boundaries \n- mutual respect \n- communication \n- reliability/consistency",\012  "friendship_values_dealbreakers": "My dealbreakers are\n- not respecting humans or nature \n- lack of accountability or awareness \n- constant negativity \n- jealousy/competition",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "Multiple times per week",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Caring",\012  "wrapping_up_ideal_friend_words_word2": "Open minded",\012  "wrapping_up_ideal_friend_words_word3": "Charismatic",\012  "wrapping_up_what_want_receive": "I would like to to receive in a friendship a long lasting connection where we ultimately become like sisters. As far as community I would like a place where I can connect with all kinds af humans and be a village for one another.",\012  "wrapping_up_gender_preference": "Woman",\012  "wrapping_up_age_preference": "Similar in age or slightly older (21-25)",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
INSERT INTO assessment VALUES(108,165,replace('{\n  "tell_us_more_what_brings_you": "I saw that you\u2019re hosting an event at sip city and I really like that place and how they\u2019re moving in the community. I am also trying to gain more of a sense of community as it\u2019s so easy to slide into isolation nowadays!",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_gender_identity_details": "Cis woman",\n  "tell_us_more_about_yourself": "I might be an ambivert, I do crave socialization but I tend to regain my energy at home with my husband, just hanging out playing cozy games watching survivor, and cuddling cats. I like to try new things and go new places but my repeat activities include game nights, an occasional night out (girls room CLT or a local show at one of the smaller venues) and playing in river water specifically lol. I have dabbled in dnd  as well.",\n  "friendship_readiness_emotional_availability": "4",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Health challenges",\n  "friendship_readiness_life_circumstances_details": "I selected health as my only barrier which isn\u2019t a lot but I wonder about my capacity for new things in general because of my off days that are caused by fatigue and pain. I would need someone that can show grace in that area and not take cancelations or time between hangouts personally!",\n  "friendship_readiness_showing_up": "Meeting in a group seeking for game nights or in a one on one hang out, I\u2019m a pretty good texter and am always down for a venting session. I do tend to be the first person to crack a joke and keep things light in this heavy world but I also think I can be there for others when they are going through something as well.",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "4",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "2",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I do have a mother wound and all of its traits so I found myself untrusting of my girl friends and have been burned in the past. I have been told I was too quick to drop people, but I have had the same friends for over 10 years now, and am both much better at meeting people where they are at and enjoying the emotional maturity of my current friends",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Learning new skills",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Medicinal herbs/substances",\n    "Video games (PC, PS, XBOX, Switch)"\n  ],\n  "hobbies_interests_hobbies_details": "I\u2019ll try anything twice! I mainly do things that don\u2019t directly align with my interests for the sake of socializing and whimsy",\n  "hobbies_interests_doing_vs_being": "It depends",\n  "values_top_values": [\n    "Empathy",\n    "Nature",\n    "Health",\n    "Fun",\n    "Gratitude",\n    "Honesty",\n    "Patience",\n    "Self-awareness",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Celebration of wins and joys"\n  ],\n  "friendship_values_non_negotiables": "People who maybe struggle with being supportive and are overly critical or easily offended I think I would be too nervous around, I have OCD and I frequently have intrusive thoughts of doing emotional harm to the people I spend time with, and critical, or highly emotional people I would rather appreciate from a distance so as not to trigger my harm ocd. Also don\u2019t love when people are really competitive( save fore a heated but still funny game related debate) ! I grew up with sisters \ud83d\ude02also on that note NO mean yelling and NO violence ofc",\n  "friendship_values_dealbreakers": "I am sorry I think I already answered this in my previous question- no mean yelling and no violence! \u201cWho yells?\u201d",\n  "friendship_values_connection_language": [\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "A good time",\n  "wrapping_up_ideal_friend_words_word2": "Accepting",\n  "wrapping_up_ideal_friend_words_word3": "Outgoing",\n  "wrapping_up_what_want_receive": "I would like to connect with people casually and go from there, I have space in my world for a handful of new friends and probably a best friend if the connection is right. I would like to meet relatively well rounded people who could maybe introduce me to new pockets of community and vice versa",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman",\n    "Non-binary",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "Similar age to me, give or take 10 years! I am 35 but think of myself as late twenties hahah",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(109,168,replace('{\n  "tell_us_more_what_brings_you": "Most of my friends live out of state and I\u2019m seeking new people to do life with. I am pretty shy so it\u2019s hard to make friends out.",\n  "tell_us_more_political_leanings": "Leftist",\n  "tell_us_more_gender_identity": "Non-binary",\n  "tell_us_more_about_yourself": "I am a nervous talker when meeting new people but I am also inquisitive so I love asking questions and learning more about people and the world. I love to read and crochet. I am also very passionate and stubborn at times.",\n  "friendship_readiness_emotional_availability": "7",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Ending a significant relationship",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Means being a listening ear and also honest when asked for opinions. It also means actually showing up whether that means to friends events or just running errands with someone.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Voice notes",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am rigid with my boundaries, sometimes to a fault",\n  "conflict_repair_friendship_lessons": "It\u2019s important that I make myself approachable for when people want to give feedback or constructive criticism.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Book clubs or discussion groups",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Writing and reflection",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Activism",\n    "Assertiveness",\n    "Social Justice",\n    "Empathy",\n    "Inclusiveness",\n    "Integrity",\n    "Self-awareness",\n    "Sexuality"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should challenge me to grow",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Integrity, commitment to making the world better, do not support abuser artists such as Chris Brown",\n  "friendship_values_dealbreakers": "\u201cArt is separate from the artist\u201d trump supporter, pro life, anti-LGBT, anti-trans, being a people pleaser to the point where you don\u2019t communicate your needs",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Other forms of support (problem-solving, providing resources like money/meals)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Smart",\n  "wrapping_up_ideal_friend_words_word3": "Fun",\n  "wrapping_up_what_want_receive": "A space to be me and show up without fear that I am not doing enough or that I am too much.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "25-33",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(110,169,replace('{\n  "tell_us_more_what_brings_you": "I saw Sip City repost the event that\u2019s happening there in June and decided to RSVP :) I\u2019ve been in Charlotte my whole life but am looking for more friendships with people who have similar interests to me. I feel like it\u2019s easy for me to get along with people but harder to have closer friendships and really want a close group of friends!",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I would describe myself as very creative, passionate about many things, and try to include everyone. I\u2019m social but it\u2019s hard for me to fully express my personality until I get to really know someone. When I\u2019m comfortable around people, I think people would describe me as funny and charismatic.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Prioritizing your friends even when it isn\u2019t easy or comfortable is very important. Obviously things come up when you\u2019re busy and can\u2019t dedicate as much time to friendships but I think it\u2019s important to be there for them in the way you would want someone to be there for you!",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Voice notes",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I\u2019ve definitely learned so much about myself especially in the past year. It\u2019s really easy for me to feel excluded and left out if I see my friends hanging out without me but I\u2019ve had to really push myself to make plans and be the one to initiate if I\u2019m feeling alone.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Therapy/personal growth work"\n  ],\n  "hobbies_interests_hobbies_details": "I\u2019m a full time artist and art is very important to me! I love hosting dinner/holiday parties with my close friends and we have wine and paint nights sometimes. I\u2019m also looking for friends to go to workout classes (solidcore/classpass/yoga) and run with!",\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Career",\n    "Creativity",\n    "Health",\n    "Fun",\n    "Genuineness",\n    "Inclusiveness",\n    "Integrity",\n    "Non-conformity"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friends should challenge me to grow",\n    "Humor and laughter are essential to friendship"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Accountability and growth",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "I am a very strong believer in the fact you are the product of the 5 people you spend the most time with. I want my friends and I to push each other to be the best versions of ourselves! Effort is important to me in friendship.",\n  "friendship_values_dealbreakers": "I don\u2019t drink that often, so someone who is looking for a friend to go out with them every night or even every weekend would be draining for me. Putting a guy you\u2019re interested in or seeing over a friend is also a dealbreaker for me, specifically if the friendship is neglected as soon as a guy is introduced. Both romantic and friendship relationships are important but they both take effort to maintain.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)",\n    "Gifts (items that remind them of you)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Loyal",\n  "wrapping_up_ideal_friend_words_word2": "Funny",\n  "wrapping_up_ideal_friend_words_word3": "Dependable",\n  "wrapping_up_what_want_receive": "I would love to find a group of friends that are dependable, have similar values to me and are looking for community as well.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "Similar age to me (20s/30s)",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(111,170,replace('{\n  "tell_us_more_what_brings_you": "I\u2019m in medical school and it\u2019s been hard to make and maintain friendships with my busy schedule",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I\u2019m very caring and understanding. I\u2019m also funny",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Health challenges"\n  ],\n  "friendship_readiness_life_circumstances_details": "Someone also in school could be nice so that we can study together. School and studying are my biggest time limits",\n  "friendship_readiness_showing_up": "Consistently reaching out or checking in",\n  "personality_social_style_recharge_style": "4",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "4",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I need structure and advanced notice",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Occasional meaningful texts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Feel hurt but bottle it up and move on",\n  "conflict_repair_repair_looks_like": [\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Big friendship breakups happen mainly from them criticizing the majority of what I do or if they stop reaching out. When I don\u2019t hear from people after I\u2019ve tried connecting I feel rejected and figure if they care they\u2019ll remember me eventually",\n  "hobbies_interests_activities_interests": [\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Sports (playing or watching)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Astrology",\n    "Therapy/personal growth work"\n  ],\n  "hobbies_interests_hobbies_details": "I have also done comedy for 5 years and do shows around town. My jokes can be filthy so I hope they don\u2019t mind",\n  "hobbies_interests_doing_vs_being": "Being: I prefer hanging out or just existing in each other''s presence",\n  "values_top_values": [\n    "Ambition",\n    "Career",\n    "Creativity",\n    "Fun",\n    "Genuineness",\n    "Inclusiveness",\n    "Integrity",\n    "Loyalty",\n    "Purpose",\n    "Resilience"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Kindness and understanding",\n  "friendship_values_dealbreakers": "putting others down. I don\u2019t like mean teasing bc while some friends can do that I\u2019ll just get my feelings hurt",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Supportive",\n  "wrapping_up_ideal_friend_words_word2": "Understanding",\n  "wrapping_up_ideal_friend_words_word3": "Consistent",\n  "wrapping_up_what_want_receive": "Companionship, acceptance, and support",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "Similar age or slightly older. Im 27 so maybe up to mid 30s",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(112,171,replace('{\n  "tell_us_more_what_brings_you": "I grew up in NY. Moved to Charlotte ten years ago when I was honestly in a bad spot mentallu so I wasn''t really focused on finding friendships. Most of those early friendships i made didnt stick it out with me. Ive been on my healing journey and I am readg to put myself out there and connect with people who may be on a similar path or just friends into tarot, crystals, music festivals, and cats. I\u2019m at a point in life where I really value genuine connections, supportive energy, and spaces where people can just be themselves and grow together. \u2764\ufe0f",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "People would describe me as chill. I am a laid back person but i do care deeply about injustice and i value fairness. I am a giving person and really like to take care of those around me. At a festival or rave I like the be the rave mother. I Always have hand sanitizer, stickers, bandaids and tissues in my purse. I am a virgo with ADHD. Basically organized chaos. I am creative and I love arts and crafts. I love watching TV and movies. I really love horror genre. I love learning about history and soecifically history through the paranormal. Overall, my loved ones would describe me as a happy, kind, fun, fairy.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "Major career transition",\n  "friendship_readiness_life_circumstances_details": "I really want a life long friendship. Just something that comes naturally and is easy for both of us. I really dont want to force anything. I remember be 14 and making friends was so natural, I would get adopted by extroverts. Now as a 30 year old its a little more difficult to find people who are on the same wavelength. I have a lot of friends just in different states or different stages of life. Just looking for a someone who would go to concerts with me, do a craft, or just come over to eat pizza and watch a movie. They must like cats!",\n  "friendship_readiness_showing_up": "Definitely time and consistency. I am available and want to do things. I would reach out and give suggestions on what to do and I also expect effort of the other person. I do think vulnerability brings people closer.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "Quality time together to reconnect",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "Some of my past friendships just naturally grew apart in different directions. Others I made the decision to stop communicating and honestly they didn''t even try to reach out after. I will put in the amount of effort I recieve.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Fashion/Styling",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_hobbies_details": "I\u2019m really into artsy/crafty hobbies. I make jewelry, resin pieces, paper earrings, laser engraved stuff, and little 3D printed creations. I love anything whimsical, colorful, or slightly weird lol. I\u2019m also into live music, art markets, thrifting, DIY projects, tarot, and honestly just trying new creative hobbies whenever I can.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Peace",\n    "Creativity",\n    "Gratitude",\n    "Honesty",\n    "Intuition",\n    "Loyalty",\n    "Patience",\n    "Resilience",\n    "Uniqueness",\n    "Thrift"\n  ],\n  "friendship_values_statements_resonate": "Mutual effort and reciprocity matters to me",\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Consistency and reliability",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "I cannot be friends with a republican. I can''t be friends with someone who bullies others. I love people who are genuinely accepting of others, kind, loving, and honest! I like to have fun and dance i would love someone who isn''t afraid to dance or who doesnt care what others think. Also they must like glitter.",\n  "friendship_values_dealbreakers": "Dishonesty, constant negativity, judgmental energy, or people who are overly draining. I really value kindness, communication, authenticity, and mutual support in friendships. I\u2019m in a phase of life where I\u2019m protecting my peace more, so I\u2019m drawn to people who are open-minded, respectful, and genuinely want good connections.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Creative",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Uplifting",\n  "wrapping_up_what_want_receive": "I\u2019d love friendships that feel supportive, genuine, and easy. People to create with, explore new things with, have meaningful conversations with, and just enjoy life around. I\u2019m looking for community that feels welcoming, inspiring, and grounded, where everyone can be themselves without judgment.",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "Similar age to me, 26- 35",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(113,174,replace('{\n  "tell_us_more_what_brings_you": "Currently I am a grad student who stays at home most of the time. I\u2019ve always wanted genuine connection but struggled to maintain them due to self-doubt. As I mature and become more emotionally available, I am challenging myself to build connections.",\n  "tell_us_more_political_leanings": "Liberal",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I would describe myself as intellectual as I enjoy deep conversations. I am thoughtful as I find meaning in all of life. I am an intro-extravert because I show up differently daily.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "Other",\n  "friendship_readiness_life_circumstances_other_text": "Grad School",\n  "friendship_readiness_life_circumstances_details": "When I get stressed I tend to isolate. This is something that I am actively working toward improving on.",\n  "friendship_readiness_showing_up": "Showing up in a friendship right now looks like vulnerability, quality time, openness, consideration, and respect.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "2",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\n  "personality_social_style_communication_preference": [\n    "Video calls",\n    "Voice notes"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I have noticed that I have a hard time setting boundaries which is something I am actively working on. I also have a hard time expressing myself but I have learned to do so. I am always open to feedback.",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Writing and reflection",\n    "Meditation/mindfulness",\n    "Nature connection and grounding",\n    "Energy work/holistic practices"\n  ],\n  "hobbies_interests_hobbies_details": "",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Assertiveness",\n    "Career",\n    "Empathy",\n    "Genuineness",\n    "Growth",\n    "Love",\n    "Patience",\n    "Responsibility",\n    "Self-awareness",\n    "Vulnerability"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "I appreciate friends who respect my need for space",\n    "Friends should accept me exactly as I am"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Intellectual stimulation",\n    "Accountability and growth",\n    "Consistency and reliability",\n    "Genuineness",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Emotionally unintelligent, dishonest, close-mindedness, irresponsibility, etc.",\n  "friendship_values_dealbreakers": "Non-growth mindset, simple-mindedness, lack of understanding.",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Intelligent",\n  "wrapping_up_ideal_friend_words_word2": "Creative",\n  "wrapping_up_ideal_friend_words_word3": "Spiritual",\n  "wrapping_up_what_want_receive": "A chance to learn myself and to have the freedom to express creatively. Consistency and the willingness to grow together.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": "22-30",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(114,176,replace('{\n  "tell_us_more_what_brings_you": "Seeking connection and community",\n  "tell_us_more_political_leanings": "Moderate",\n  "tell_us_more_gender_identity": "Man",\n  "tell_us_more_about_yourself": "I am a recent new yogi, woo woo and spiritually open sensitive soul seeking community. Leaving my world behind me is hard and I am seeking to find my new one!",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Major career transition",\n  "friendship_readiness_life_circumstances_details": "I am more open and less dogmatic. It has been a helpful transition",\n  "friendship_readiness_showing_up": "Being consistent. Making sure people know that you value them",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "1",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I prefer concrete plans with minimal wiggle room",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Texting throughout the day"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": "Time and space before reconnecting",\n  "conflict_repair_flaky_friend_scenario": "Address it directly:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "Time heals",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Sports (playing or watching)",\n    "Writing (journaling, poetry, books)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Meditation/mindfulness"\n  ],\n  "hobbies_interests_hobbies_details": "N/A",\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Social Justice",\n    "Harmony",\n    "Peace",\n    "Empathy",\n    "Creativity",\n    "Independence",\n    "Integrity",\n    "Non-conformity"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friendship is about celebrating each other''s wins",\n    "I value friends who check in consistently"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times"\n  ],\n  "friendship_values_non_negotiables": "Breaking up other friendships",\n  "friendship_values_dealbreakers": "If they support Chelsea FC lol",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "compassionate",\n  "wrapping_up_ideal_friend_words_word3": "Female",\n  "wrapping_up_what_want_receive": "Authentic connection",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "21-55",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(115,178,replace('{\n  "tell_us_more_what_brings_you": "I have very strong friendships, but we\u2019re all at different stages in life and it\u2019s hard to find time to do things together. I\u2019m definitely a homebody if left to my own devices and I want to experience more of what Charlotte has to offer, so I want to find more friends to do stuff with!",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "Outgoing introvert. My friends describe me as bubbly and witty but my social battery drains pretty quickly, so I appreciate chill downtime as well. I\u2019m neurodivergent so I\u2019m always bouncing from subject to subject in conversations.",\n  "friendship_readiness_emotional_availability": "10",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "I try not to have rigid expectations of a friend \u201cshowing up\u201d for me because life happens. What I look for in a friend (and for how I treat them) is just someone who is open and comfortable in who they are so that way we make a more authentic connection.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Try to understand the other person''s perspective",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "5",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "I feel like I have pretty good intuition when meeting someone to be able to sus out if there\u2019s going to be potential issues. However, I\u2019m a big believer in second chances, but not third chances. If a true conflict arises, I\u2019m typically very understanding and willing to work through it, but if that same conflict arises again then I\u2019m pretty quick to cut off the connection.",\n  "hobbies_interests_activities_interests": [\n    "Yoga/Pilates",\n    "Writing (journaling, poetry, books)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Philosophy and deep conversations",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_hobbies_details": "I\u2019m VERY into reality TV, specifically Bravo shows, and desperately would love someone to talk to about them.",\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values": [\n    "Social Justice",\n    "Creativity",\n    "Health",\n    "Fun",\n    "Spirituality",\n    "Inclusiveness",\n    "Independence",\n    "Self-awareness",\n    "Thrift"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friendship is about celebrating each other''s wins",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences"\n  ],\n  "friendship_values_non_negotiables": "Must have similar morals/views when it comes to today\u2019s political climate, someone who wants to go out and explore new experiences, someone who I can easily talk to about anything that comes to my mind",\n  "friendship_values_dealbreakers": "Someone who is constantly going out to bars/clubs (I\u2019m 31 and get week-long hangovers lol), someone who is very religious, someone who has kids (I\u2019m single and childfree, so the lifestyle would just be too different)",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "Multiple times per week",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Funny",\n  "wrapping_up_ideal_friend_words_word2": "Neurodivergent",\n  "wrapping_up_ideal_friend_words_word3": "Considerate",\n  "wrapping_up_what_want_receive": "A support system, someone to talk to about random things, someone down to explore new things with me",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "28-35ish",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(116,179,replace('{\n  "tell_us_more_what_brings_you": "I moved to Charlotte about 4 years ago from NY. Most of my friends live in NY and typically visit me or vice versa. I would love to make friends here. I have made a couple on my own but I\u2019d like to expand my circle a bit.",\n  "tell_us_more_political_leanings": [\n    "Liberal",\n    "Leftist"\n  ],\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I am very down to earth and honest person. I find the little things in life exciting. Although I love the outdoors, my health conditions doesn\u2019t allow me to enjoy it like how I used to (hiking or swimming). I still make the attempts to travel to the best of my abilities. I am kind and I enjoy eating as much as I enjoy cooking. I enjoy getting into my creative side with coloring. I enjoy watching foreign movies and anime (by myself and with my husband). Currently, I am enrolled in a course to get my medical coding certification.",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "Health challenges",\n  "friendship_readiness_life_circumstances_details": "I have to rely on my husband to drive around because of my health condition. If he\u2019s not available, I take the uber or open to being picked up once trust is developed.",\n  "friendship_readiness_showing_up": "Listening, giving positive feedback, catching up with life, sharing old memories with one another, joking around without hurting one another, and thinking before speaking.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I tend to let things bottle up. I have tried getting better at it by addressing the matter asap but at times I don\u2019t think it\u2019s beneficial for me to do that since I don\u2019t want to say the wrong thing in the heat of the moment.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_hobbies_details": "I love to listen to other people\u2019s travel plans and travel history. I prefer someone who also watches anime or murder mysteries for fun.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values": [\n    "Family (chosen or biological)",\n    "Community",\n    "Loyalty",\n    "Love",\n    "Responsibility",\n    "Resilience",\n    "Self-awareness",\n    "Self-expression",\n    "Stability",\n    "Wisdom"\n  ],\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Friendship is about celebrating each other''s wins",\n    "Friends should challenge me to grow"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "I want a friendship that will help me grow as a person and vice versa. Someone who will lift me up and I can do that for them too. Honesty is the best policy. I want great shared experiences (with shopping, conversation and intellect)",\n  "friendship_values_dealbreakers": "No racism, no anti-Islamic remarks, cannot barge into my home without notice, cannot interfere with my marriage and relationship with sisters, absolutely no body shaming, no past shaming, no comparing!",\n  "friendship_values_connection_language": [\n    "Quality time (hangouts, phone calls, etc)",\n    "Words of affirmation (encouragement, posts about you)",\n    "Emotional Support (showing up in hard times, being a listening ear)"\n  ],\n  "logistics_connection_frequency": "A few times a month",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Hilarious",\n  "wrapping_up_ideal_friend_words_word3": "Intelligent",\n  "wrapping_up_what_want_receive": "Security, trust and peace",\n  "wrapping_up_gender_preference": "Woman",\n  "wrapping_up_age_preference": "28-45",\n  "wrapping_up_open_to_multiple_matches": [\n    "Yes, I''m open to connecting with multiple people",\n    "Yes, I''m open to connecting with multiple people"\n  ]\n}','\n',char(10)),0,NULL);
INSERT INTO assessment VALUES(117,183,replace('{\n  "tell_us_more_what_brings_you": "I moved to Charlotte one year ago! I currently live with my husband in Pineville with my 11 year old dog Ricky.  \ud83d\udc36 I currently work in the restaurant industry and have been wanting to make friends ever since moving here.",\n  "tell_us_more_political_leanings": "Apolitical",\n  "tell_us_more_gender_identity": "Woman",\n  "tell_us_more_about_yourself": "I am very shy at first but open up once I am comfortable. I\u2019m adventurous and spontaneous.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Abundant capacity (I have space, time, and energy to invest)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "I\u2019ve always struggled with meeting people that stay consistent. I want the energy I put into a friendship to be reciprocated and don\u2019t want to be the only one putting into it.",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "1",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": "Mix of everything/I''m flexible",\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Address it directly and as soon as possible",\n  "conflict_repair_repair_looks_like": [\n    "A direc