INSERT INTO assessment VALUES(119,185,replace('{\012  "tell_us_more_what_brings_you": "I\u2019m a year post grad and ready to start making friends during this new chapter! I\u2019m also doing this event as an investment into myself. My social life and making friendships are becoming a priority for me.",\012  "tell_us_more_political_leanings": "Liberal",\012  "tell_us_more_gender_identity": "Woman",\012  "tell_us_more_gender_identity_details": "Cis woman",\012  "tell_us_more_about_yourself": "I would describe myself as kind, compassionate, and funny. I\u2019m an eldest daughter/sister, so I can be very ambitious and leadership oriented. \n\nLoved one\u2019s would describe me as intelligent, helpful, friendly, and humorous/quick witted (Per my boyfriend)!",\012  "friendship_readiness_emotional_availability": "9",\012  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\012  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": [\012    "Recent/upcoming move",\012    "Major career transition"\012  ],\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "Showing up, to me, means showing up for your friend in the ways that they need you to. It means devoting your time and energy to the best of your abilities to make sure they feel important, seen, and taken care of.",\012  "personality_social_style_recharge_style": "3",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "1",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "3",\012  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\012  "personality_social_style_communication_preference": [\012    "Texting throughout the day",\012    "Video calls"\012  ],\012  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Feel hurt but not saying anything, hoping it doesn''t happen again",\012  "conflict_repair_feedback_comfort": "3",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "I\u2019ve never really had any negative friendship experiences.",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Running/Cycling",\012    "Writing (journaling, poetry, books)",\012    "Music (playing, creating, deeply listening)",\012    "Exploring local spots (cafes, shops)",\012    "Reading (fiction, non-fiction, audiobooks)",\012    "Philosophy and deep conversations",\012    "Writing and reflection",\012    "Meditation/mindfulness",\012    "Therapy/personal growth work"\012  ],\012  "hobbies_interests_hobbies_details": "Going out for dinner and drinks is my favorite thing to do. I love going to the movies (but I do have some commentary during the film  just fyi). I love getting smoothies and going to the park! I like to watch TV with other people (especially reality tv).",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values": [\012    "Empathy",\012    "Creativity",\012    "Fun",\012    "Genuineness",\012    "Growth",\012    "Trust",\012    "Integrity",\012    "Loyalty",\012    "Self-awareness",\012    "Self-expression"\012  ],\012  "friendship_values_statements_resonate": [\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me",\012    "I value friends who share my worldview and values"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "Must be liberal or left leaning with an overall care and empathy for people. \n\nI also won\u2019t be friends with people who are dishonest, or are aggressive/violent.",\012  "friendship_values_dealbreakers": "Lying, being inconsiderate, being too judgmental (everyone likes a little goss, but keep it cute). \n\nRude to staff and servers absolutely not. And PLEASE!!! NO PICK ME\u2019S!!!!\ud83d\ude2d",\012  "friendship_values_connection_language": [\012    "Quality time (hangouts, phone calls, etc)",\012    "Words of affirmation (encouragement, posts about you)",\012    "Emotional Support (showing up in hard times, being a listening ear)"\012  ],\012  "logistics_connection_frequency": "I am open",\012  "logistics_connection_type": "Mix of both",\012  "wrapping_up_ideal_friend_words_word1": "Aware",\012  "wrapping_up_ideal_friend_words_word2": "Empathetic",\012  "wrapping_up_ideal_friend_words_word3": "Funny",\012  "wrapping_up_what_want_receive": "I\u2019d love to meet people and make new friends. It would be cool to have a friend group as well. But I look forward to meeting new people!",\012  "wrapping_up_gender_preference": "Woman",\012  "wrapping_up_age_preference": "Preferably close in age to me (I\u2019m turning 24) but still open!",\012  "wrapping_up_open_to_multiple_matches": [\012    "Yes, I''m open to connecting with multiple people",\012    "Yes, I''m open to connecting with multiple people"\012  ]\012}','\012',char(10)),0,NULL);
