INSERT INTO reviewer_assessment VALUES(4,'Jina','she/her','26-35','92833',replace('{\n  "basics_name": "Jina ",\n  "basics_pronouns": "she/her",\n  "basics_age_range": "26-35",\n  "basics_location": "92833",\n  "tell_us_more_what_brings_you": "I feel that I am in a transitional stage of my life as I''m entering my late 20s. I''ve stopped dating and stopped seeing people in general because I wanted to focus on myself. After this year long journey, I can''t say I''ve gotten too much out of it, but it''s fun getting to intimately know all of my quirks. Although I feel very stable by myself, I feel very insecure socially. I''m not so interested in making friends, but I love meeting people who instantly click with me. Some of those people are my lifelong friends. I''m here because my friend posted a story asking for participants and it seemed interesting and cute.",\n  "tell_us_more_friendship_meaning": "I wish I placed more importance on friendships. Humans are meant for bonds and relationships. Friends are also a part of your identity and shapes your personality. The most fulfilling friendships I''ve had in my life were with people I could show them my entire being and they''ll still love me, as I love them. Mutual vulnerability can be so beautiful. I''ve been having a hard time opening up to people, so I haven''t been able to experience the joys of all that lately. When I am ready to see them though, it''ll be a beautiful experience.",\n  "friendship_readiness_emotional_availability": "1",\n  "friendship_readiness_time_energy_capacity": "Very limited capacity (life is a lot right now)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "I have not done personal work around this",\n  "friendship_readiness_life_circumstances": [\n    "Health challenges",\n    "Other"\n  ],\n  "friendship_readiness_life_circumstances_other_text": "Depression",\n  "friendship_readiness_life_circumstances_details": "Depression made me lose interest in social things. I go out maybe once or twice a month.",\n  "friendship_readiness_showing_up": "Showing up can mean noticing things about someone that may be off and reaching out to see if they''re okay. Celebrating them when things are good. Being present and keeping up regularly through chats or calls.",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "I''m quiet at first but warm up over time",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Occasional meaningful texts"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in: ",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_hurt_feelings_needs_0": "1",\n  "conflict_repair_hurt_feelings_needs_1": "2",\n  "conflict_repair_hurt_feelings_needs_2": "4",\n  "conflict_repair_hurt_feelings_needs_3": "3",\n  "conflict_repair_hurt_feelings_needs_4": "5",\n  "conflict_repair_boundary_setting": "I am flexible with my boundaries",\n  "conflict_repair_friendship_lessons": "I have been ghosted for lack of presence/interest.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness"\n  ],\n  "hobbies_interests_want_to_try": "Learn how to do things together like making music, flower arrangement classes, ceramics classes, etc.",\n  "hobbies_interests_free_time": "Journaling, learning recipes, watching anime, drawing, traveling",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values_0": "9",\n  "values_top_values_1": "4",\n  "values_top_values_2": "10",\n  "values_top_values_3": "3",\n  "values_top_values_4": "1",\n  "values_top_values_5": "2",\n  "values_top_values_6": "7",\n  "values_top_values_7": "8",\n  "values_top_values_8": "5",\n  "values_top_values_9": "6",\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "Friends should challenge me to grow",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Calming personality, introverted, progressive, cares about environment, artistic, funny, silly",\n  "friendship_valu