INSERT INTO reviewer_assessment VALUES(5,'Aleyris','she/her','26-35','Concord',replace('{\n  "basics_name": "Aleyris",\n  "basics_pronouns": "she/her",\n  "basics_age_range": "26-35",\n  "basics_location": "Concord",\n  "tell_us_more_what_brings_you": "Very single and I have no single friends! ",\n  "tell_us_more_friendship_meaning": "Being there for each other through thick and thin. Be a nonjudgmental listening ear.",\n  "friendship_readiness_emotional_availability": "9",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am open to friendships, but want to take it slow",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": [\n    "Major career transition",\n    "Other"\n  ],\n  "friendship_readiness_life_circumstances_other_text": "School, gym time are priorities ",\n  "friendship_readiness_life_circumstances_details": "I am willing to make time for someone that also would like to make time. I have a busy schedule and I have limited time to spare, but I would love to open it up to some friendships.",\n  "friendship_readiness_showing_up": "Time, energy, consistency, vulnerability, honesty ",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Share openly and engage actively with most people",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "3",\n  "personality_social_style_ideal_hangout_2": "1",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I need structure and advanced notice",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in: ",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_hurt_feelings_needs_0": "3",\n  "conflict_repair_hurt_feelings_needs_1": "5",\n  "conflict_repair_hurt_feelings_needs_2": "4",\n  "conflict_repair_hurt_feelings_needs_3": "2",\n  "conflict_repair_hurt_feelings_needs_4": "1",\n  "conflict_repair_boundary_setting": "I am learning how to set them, but it''s still hard",\n  "conflict_repair_friendship_lessons": "I always do more for my friends and they do for me. I always check in with my friends, but don\u2019t get that back.",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Sports (playing or watching)",\n    "Rock climbing/adventure sports"\n  ],\n  "hobbies_interests_want_to_try": "I\u2019m very into fitness so something regarding fitness and spirituality",\n  "hobbies_interests_free_time": "Gym or at home",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values_0": "5",\n  "values_top_values_1": "6",\n  "values_top_values_2": "10",\n  "values_top_values_3": "2",\n  "values_top_values_4": "4",\n  "values_top_values_5": "9",\n  "values_top_values_6": "8",\n  "values_top_values_7": "3",\n  "values_top_values_8": "7",\n  "values_top_values_9": "1",\n  "friendship_values_statements_resonate": [\n    "I value friends who check in consistently",\n    "I value reliability and follow-through",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Celebration of wins and joys",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Reciprocity and effort",\n  "friendship_values_dealbreakers": "Constant canceling, no texts back, can\u2019t understand basic human rights are for everyone ",\n  "friendship_values_connection_language_0": "4",\n  "friendship_values_connection_language_1": "1",\n  "friendship_values_connection_language_2": "6",\n  "friendship_values_connection_language_3": "5",\n  "friendship_values_connection_language_4": "2",\n  "friendship_values_connection_language_5": "3",\n  "logistics_connection_frequency": "I am open",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Hilarious",\n  "wrapping_up_ideal_friend_words_word2": "Nurturing ",\n  "wrapping_up_ideal_friend_words_word3": "Reciprocal",\n  "wrapping_up_what_can_offer": "A fun time, a shoulder to lean on, someone that values human connections, fast texter, honest",\n  "wrapping_up_what_want_receive": "A group of friends that want nothing but the best for everyone they come in contact with ",\n  "wrapping_up_gender_preference": [\n    "Man",\n    "Woman",\n    "Non-binary",\n    "No preference"\n  ],\n  "wrapping_up_age_preference": [\n    "26-35",\n    "36-45"\n  ],\n  "feedback_reviewer_rating": "9",\n  "feedback_reviewer_feedback_positive": "The variety of questions to make us think of what to put",\n  "feedback_reviewer_feedback_improvements": [\n    "Kinda long ",\n    "Kinda long "\n  ]\n}','\n',char(10)),'2025-10-14 02:08:15.118833',0,'oops age question twice?');
INSERT INTO reviewer_assessment VALUES(6,'Alex Washburn','she/her','26-35','28203',replace('{\012  "basics_name": "Alex Washburn",\012  "basics_pronouns": "she/her",\012  "basics_age_range": "26-35",\012  "basics_location": "28203",\012  "tell_us_more_what_brings_you": "I\u2019m seeking friends that love to spend a lot of in between time together (eg. can be together and do nothing and enjoy it). As an adult that is harder to come by because we are all working so much! ",\012  "tell_us_more_friendship_meaning": "Hmm friendship is the most fundamental experience of love that I have ever had. ",\012  "friendship_readiness_emotional_availability": "5",\012  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\012  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\012  "friendship_readiness_personal_work": "I am actively working on it now",\012  "friendship_readiness_life_circumstances": [\012    "Major career transition",\012    "Other"\012  ],\012  "friendship_readiness_life_circumstances_other_text": "Samba/Capoeira schedule is unpredictable so I often have to make in the moment plans vs. far ahead plans ",\012  "friendship_readiness_life_circumstances_details": "",\012  "friendship_readiness_showing_up": "For me spending regular time in person is a big factor that I prefer/prioritize (vs. texting) ",\012  "personality_social_style_recharge_style": "5",\012  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\012  "personality_social_style_ideal_hangout_0": "3",\012  "personality_social_style_ideal_hangout_1": "2",\012  "personality_social_style_ideal_hangout_2": "4",\012  "personality_social_style_ideal_hangout_3": "1",\012  "personality_social_style_making_plans": "I thrive on spontaneity and going with the flow",\012  "personality_social_style_communication_preference": [\012    "Voice notes",\012    "Primarily in-person hangouts"\012  ],\012  "personality_social_style_texting_style": "I prefer less frequent but more meaningful exchanges",\012  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\012  "conflict_repair_repair_looks_like": [\012    "A direct conversation about what happened",\012    "Quality time together to reconnect",\012    "Acknowledgement of impact and sincere apology",\012    "Humor and lightness to ease back in"\012  ],\012  "conflict_repair_flaky_friend_scenario": "Address it directly: ",\012  "conflict_repair_feedback_comfort": "4",\012  "conflict_repair_hurt_feelings_needs_0": "5",\012  "conflict_repair_hurt_feelings_needs_1": "1",\012  "conflict_repair_hurt_feelings_needs_2": "4",\012  "conflict_repair_hurt_feelings_needs_3": "2",\012  "conflict_repair_hurt_feelings_needs_4": "3",\012  "conflict_repair_boundary_setting": "It depends on the friendship",\012  "conflict_repair_friendship_lessons": "I have learned that for me it is very possible to go through periods of disconnection with friends and feel hurt for a while and still reconnect after depending on the situation so I am incredible slow to end a friendship. In fact I don\u2019t think I\u2019ve ever ended a friendship, just have had to set certain boundaries in terms of closeness with some in order to maintain a relationship. I am able to maintain long distance friendships but because I have multiple long distance friend groups it is realistically not possible to have them all on the same level of investment so some have naturally waned depending on each of our lives. \r\n\r\nEarly in my life I had friendships where others were consistently relying on me for emotional and practical support and I was not relying on them at all - it was imbalanced and resembled codependency as I wanted to be needed. After high school I worked through this pattern and built non codependent friendships in college and beyond. Sometimes that pattern pops up depending on the person but I can usually spot it early on now. \r\n\r\nI also feel I have a good sense of when people want to invest in a friendship with me and when they don\u2019t. I try to give it a few tries to build and I don\u2019t mind being an initiator but if eventually it feels like pulling teeth, I tend to take that as either they don\u2019t want to build on the friendship with me or don\u2019t have the capacity to and I can honor that even if it isn\u2019t what I hoped for. I learned in middle school that chasing friendships is draining for all parties involved. \r\n\r\nI have also learned that some friendships are there for just a season which can be beautiful even if also heartbreaking. ",\012  "hobbies_interests_activities_interests": [\012    "Hiking/nature walks",\012    "Dancing (salsa, pole, aerial, casual, etc)",\012    "Writing (journaling, poetry, books)",\012    "Music (playing, creating, deeply listening)",\012    "Volunteering/advocacy",\012    "Attending events (concerts, markets, etc)",\012    "Exploring local spots (cafes, shops)",\012    "Philosophy and deep conversations",\012    "Learning new skills",\012    "Writing and reflection",\012    "Activism and social change",\012    "Religious gatherings (temple/church/mosque, etc)",\012    "Therapy/personal growth work",\012    "Nature connection and grounding",\012    "Energy work/holistic practices"\012  ],\012  "hobbies_interests_want_to_try": "Trying BIPOC/LGBTQ+ owned spots \r\n\r\nThrifting",\012  "hobbies_interests_free_time": "Dance, martial arts, resting/chatting",\012  "hobbies_interests_doing_vs_being": "Both",\012  "values_top_values_0": "4",\012  "values_top_values_1": "9",\012  "values_top_values_2": "10",\012  "values_top_values_3": "8",\012  "values_top_values_4": "5",\012  "values_top_values_5": "7",\012  "values_top_values_6": "6",\012  "values_top_values_7": "1",\012  "values_top_values_8": "2",\012  "values_top_values_9": "3",\012  "friendship_values_statements_resonate": [\012    "I value reliability and follow-through",\012    "Humor and laughter are essential to friendship",\012    "Mutual effort and reciprocity matters to me"\012  ],\012  "friendship_values_friendship_needs": [\012    "Emotional depth and vulnerability",\012    "Shared laughter and lightness",\012    "Intellectual stimulation",\012    "Mutual support during hard times",\012    "Celebration of wins and joys",\012    "Accountability and growth",\012    "Non-judgment and acceptance",\012    "Consistency and reliability",\012    "Genuineness",\012    "Adventure and new experiences",\012    "Peaceful, easy presence"\012  ],\012  "friendship_values_non_negotiables": "Actively working to be anti racist, intersectionally feminist, queer affirming (will state out loud that they are working toward those things and always will be)",\012  "friendship_values_dealbreakers": "The opposite of the previous question. \r\n\r\nAlso if their words and actions don\u2019t align. ",\012  "friendship_values_connection_language_0": "1",\012  "friendship_values_connection_language_1": "6",\012  "friendship_values_connection_language_2": "5",\012  "friendship_values_connection_language_3": "2",\012  "friendship_values_connection_language_4": "3",\012  "friendship_values_connection_language_5": "4",\012  "logistics_connection_frequency": "Multiple times per week",\012  "logistics_connection_type": "Primarily in-person connections",\012  "wrapping_up_ideal_friend_words_word1": "High level of integrity ",\012  "wrapping_up_ideal_friend_words_word2": "Fun and weird and silly",\012  "wrapping_up_ideal_friend_words_word3": "Gentle ",\012  "wrapping_up_what_can_offer": "Integrity, thoughtfulness, spontaneity, fun/weird/laughter, compassion",\012  "wrapping_up_what_want_receive": "Integrity, thoughtfulness, spontaneity, fun/weird/laughter, compassion",\012  "wrapping_up_gender_preference": "No preference",\012  "wrapping_up_age_preference": "26-35",\012  "feedback_reviewer_rating": "10",\012  "feedback_reviewer_feedback_positive": "Easy/smooth",\012  "feedback_reviewer_feedback_improvements": [\012    "The age question happened twice but literally everything else is perfect ",\012    "The age question happened twice but literally everything else is perfect "\012  ]\012}','\012',char(10)),'2025-10-14 02:36:17.392117',0,NULL);
INSERT INTO reviewer_assessment VALUES(7,'Courtney','she/her','26-35','28203',replace('{\n  "basics_name": "Courtney ",\n  "basics_pronouns": "she/her",\n  "basics_age_range": "26-35",\n  "basics_location": "28203",\n  "tell_us_more_what_brings_you": "Supporting one of my bestest friends in the whole world ",\n  "tell_us_more_friendship_meaning": "Community, support, strength, accountability, mirrors",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Good capacity (I''m ready to prioritize friendships)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "I think time is a big factor as well. Scheduling and being consistent in order to nurture new relationships can be really hard for me because I really only have capacity to hang on the weekends and that\u2019s only 2 days out of the week!",\n  "friendship_readiness_showing_up": "Consistency, time, being vulnerable and open",\n  "personality_social_style_recharge_style": "2",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "3",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "2",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Primarily in-person hangouts"\n  ],\n  "personality_social_style_texting_style": "Quick responder, love ongoing conversations",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Written communication (text, letter, etc)",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology",\n    "Time and space before reconnecting",\n    "Humor and lightness to ease back in"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Pull back and wait to see if they reach out or notice",\n  "conflict_repair_feedback_comfort": "2",\n  "conflict_repair_hurt_feelings_needs_0": "1",\n  "conflict_repair_hurt_feelings_needs_1": "2",\n  "conflict_repair_hurt_feelings_needs_2": "4",\n  "conflict_repair_hurt_feelings_needs_3": "5",\n  "conflict_repair_hurt_feelings_needs_4": "3",\n  "conflict_repair_boundary_setting": "I struggle with boundaries and often overextend",\n  "conflict_repair_friendship_lessons": "I\u2019m very avoidant and will sometimes allow friendships to fall apart if I notice a pattern and don\u2019t feel cared for. I can be really stubborn and not reach out if I feel like I\u2019ve been wronged ",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Yoga/Pilates",\n    "Running/Cycling",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Sports (playing or watching)",\n    "Rock climbing/adventure sports",\n    "Writing (journaling, poetry, books)",\n    "Visual arts (painting, drawing, photography)",\n    "Music (playing, creating, deeply listening)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Volunteering/advocacy",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Writing and reflection",\n    "Activism and social change",\n    "Meditation/mindfulness",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding",\n    "Energy work/holistic practices",\n    "Medicinal herbs/substances"\n  ],\n  "hobbies_interests_want_to_try": "Workout classes ",\n  "hobbies_interests_free_time": "Reading, watching shows, baking, gaming ",\n  "hobbies_interests_doing_vs_being": "Doing: I love activities, adventures, and experiences with friends",\n  "values_top_values_0": "8",\n  "values_top_values_1": "9",\n  "values_top_values_2": "7",\n  "values_top_values_3": "4",\n  "values_top_values_4": "10",\n  "values_top_values_5": "6",\n  "values_top_values_6": "1",\n  "values_top_values_7": "3",\n  "values_top_values_8": "5",\n  "values_top_values_9": "2",\n  "friendship_values_statements_resonate": [\n    "I value reliability and follow-through",\n    "Humor and laughter are essential to friendship",\n    "Mutual effort and reciprocity matters to me"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Mutual support during hard times",\n    "Non-judgment and acceptance",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Empathy, similar political views, open-mindedness, kindness ",\n  "friendship_values_dealbreakers": "Man-centered, taking way more than giving ",\n  "friendship_values_connection_language_0": "1",\n  "friendship_values_connection_language_1": "5",\n  "friendship_values_connection_language_2": "3",\n  "friendship_values_connection_language_3": "2",\n  "friendship_values_connection_language_4": "6",\n  "friendship_values_connection_language_5": "4",\n  "logistics_connection_frequency": "Once a week",\n  "logistics_connection_type": "Primarily in-person connections",\n  "wrapping_up_ideal_friend_words_word1": "Empathetic ",\n  "wrapping_up_ideal_friend_words_word2": "Energetic ",\n  "wrapping_up_ideal_friend_words_word3": "Kind ",\n  "wrapping_up_what_can_offer": "Kindness, consistency, support ",\n  "wrapping_up_what_want_receive": "Non-judgement, excitement, laughter ",\n  "wrapping_up_gender_preference": "No preference",\n  "wrapping_up_age_preference": "26-35",\n  "feedback_reviewer_rating": "10",\n  "feedback_reviewer_feedback_positive": "The ability to reflect on what I need and what I can give in friendships ",\n  "feedback_reviewer_feedback_improvements": [\n    "None this is perfect, maybe add schedule/time as a barrier to building friendship. And finances if that\u2019s not on there already!",\n    "None this is perfect, maybe add schedule/time as a barrier to building friendship. And finances if that\u2019s not on there already!"\n  ]\n}','\n',char(10)),'2025-10-15 02:06:21.052787',0,'Obsessed with this result. I do agree -- adding finances or work to the barriers to friendship.');
INSERT INTO reviewer_assessment VALUES(8,'Tess!','she/they','26-35','Winston-Salem',replace('{\n  "basics_name": "Tess!",\n  "basics_pronouns": "she/they",\n  "basics_age_range": "26-35",\n  "basics_location": "Winston-Salem",\n  "tell_us_more_what_brings_you": "My wonderful friend started this community and I want to support her!!",\n  "tell_us_more_friendship_meaning": "Friendship to me is acceptance, love, and safety in a person and the dynamic that person has with you! My true friends will always have my back but also call me out on my shit when they need to. Friendship is a connection with a person who has the same vibe as you, is as weird as you, and will always make you feel seen and included. ",\n  "friendship_readiness_emotional_availability": "8",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I am actively seeking close, intimate friendships",\n  "friendship_readiness_personal_work": "I am actively working on it now",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "As a neurodivergent person I''d need my friends to understand that while I might not text everyday I''m still thinking of them. I also have a lot of weird hyperfixations and would like a friend who even if they aren''t interested in it would be willing to listen to me ramble. ",\n  "friendship_readiness_showing_up": "Listen to me ramble about my hyperfixations even if it''s not something they care a lot about, allow me to be vulnerable with them and also allowing themselves to be vulnerable with me, willing to make time to spend together",\n  "personality_social_style_recharge_style": "3",\n  "personality_social_style_social_settings": "Somewhere in between \u2013 depends on the vibe",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "4",\n  "personality_social_style_ideal_hangout_3": "3",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Texting throughout the day",\n    "Mix of everything/I''m flexible"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Prefer to avoid direct confrontation if possible",\n  "conflict_repair_repair_looks_like": [\n    "A direct conversation about what happened",\n    "Quality time together to reconnect",\n    "Acts of care and presence",\n    "Acknowledgement of impact and sincere apology"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in: ",\n  "conflict_repair_feedback_comfort": "4",\n  "conflict_repair_hurt_feelings_needs_0": "3",\n  "conflict_repair_hurt_feelings_needs_1": "5",\n  "conflict_repair_hurt_feelings_needs_2": "1",\n  "conflict_repair_hurt_feelings_needs_3": "2",\n  "conflict_repair_hurt_feelings_needs_4": "4",\n  "conflict_repair_boundary_setting": "It depends on the friendship",\n  "conflict_repair_friendship_lessons": "I notice that I often blame myself for the rupture even if it''s not something that I caused. I''ve also noticed that I tend to give more chances than I probably should. I''ve learned that it''s okay for me to expect a certain amount of energy to be returned (not necessarily equal but not like 10% or 20%). I''ve had a few friendships end due to a difference in values and ethics when I was in undergrad. ",\n  "hobbies_interests_activities_interests": [\n    "Hiking/nature walks",\n    "Dancing (salsa, pole, aerial, casual, etc)",\n    "Visual arts (painting, drawing, photography)",\n    "Crafting (pottery, knitting, DIY, etc)",\n    "Cooking/Baking",\n    "Hosting gatherings (dinner parties, game nights)",\n    "Book clubs or discussion groups",\n    "Attending events (concerts, markets, etc)",\n    "Exploring local spots (cafes, shops)",\n    "Reading (fiction, non-fiction, audiobooks)",\n    "Podcasts and documentaries",\n    "Philosophy and deep conversations",\n    "Learning new skills",\n    "Activism and social change",\n    "Tarot/oracle cards",\n    "Astrology",\n    "Therapy/personal growth work",\n    "Nature connection and grounding"\n  ],\n  "hobbies_interests_want_to_try": "Rock climbing or a music festival/rave",\n  "hobbies_interests_free_time": "With my cats, reading, crafting, listening to podcasts, watching TV or movies. I try to go to at least 2 social gatherings a month, and try to do one activity outside of my home a week; usually some try of art or craft group, coffeeshop, or citywide event.",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values_0": "2",\n  "values_top_values_1": "10",\n  "values_top_values_2": "3",\n  "values_top_values_3": "4",\n  "values_top_values_4": "6",\n  "values_top_values_5": "8",\n  "values_top_values_6": "7",\n  "values_top_values_7": "1",\n  "values_top_values_8": "9",\n  "values_top_values_9": "5",\n  "friendship_values_statements_resonate": [\n    "Friends should be able to have difficult conversations",\n    "Mutual effort and reciprocity matters to me",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Intellectual stimulation",\n    "Mutual support during hard times",\n    "Accountability and growth",\n    "Non-judgment and acceptance",\n    "Genuineness",\n    "Adventure and new experiences",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables": "Same values, morals, and ethics especially in regards to today''s sociopolitical environment. If you voted to take away the rights of marginalized communities or you are in a relationship with someone who voted that way I don''t want to be a part of that social circle. ",\n  "friendship_values_dealbreakers": "Saying negative things about a mutual friend that is either untrue or unproven. If I feel drained emotionally and/or mentally after spending time with someone and we didn''t specifically do anything draining I likely won''t want to continue spending time with that person. If I am constantly and consistently giving parts of myself and my energy into maintaining a friendship without any return I''ll get the hint and step back. ",\n  "friendship_values_connection_language_0": "2",\n  "friendship_values_connection_language_1": "1",\n  "friendship_values_connection_language_2": "4",\n  "friendship_values_connection_language_3": "3",\n  "friendship_values_connection_language_4": "5",\n  "friendship_values_connection_language_5": "6",\n  "logistics_connection_frequency": "Quality over quantity \u2013 frequency matters less than depth",\n  "logistics_connection_type": "Mix of both",\n  "wrapping_up_ideal_friend_words_word1": "Kind",\n  "wrapping_up_ideal_friend_words_word2": "Genuine",\n  "wrapping_up_ideal_friend_words_word3": "Funny",\n  "wrapping_up_what_can_offer": "I feel like I can offer emotional support, a cheerleader in your corner, a person to try new things with, someone to go on adventures with, a shoulder to cry on, a person to be quiet with",\n  "wrapping_up_what_want_receive": "Connection, support, love, someone to pull me out of my comfort zone, someone I can be quiet with, I would like to feel recharged after spending time with my friend(s) and/or community.",\n  "wrapping_up_gender_preference": [\n    "Woman",\n    "Non-binary"\n  ],\n  "wrapping_up_age_preference": "26-35",\n  "feedback_reviewer_rating": "9",\n  "feedback_reviewer_feedback_positive": "The ability to explain and to also check more than one answer (I''m suuuuuupppper indecisive)",\n  "feedback_reviewer_feedback_improvements": [\n    "While I think the length of the assessment makes sense to get an accurate result, I also think most people don''t like assessments that are more than 20 questions.",\n    "While I think the length of the assessment makes sense to get an accurate result, I also think most people don''t like assessments that are more than 20 questions."\n  ]\n}','\n',char(10)),'2025-10-15 02:22:06.808052',1,'Hmmm I think I agree with the length in some regard, but also feel as if it''s better to get a lot of unnecessary information than not enough.');
