INSERT INTO reviewer_assessment VALUES(11,'Jalen Young','he/him','26-35','Charlotte, NC',replace('{\n  "basics_name": "Jalen Young",\n  "basics_pronouns": "he/him",\n  "basics_age_range": "26-35",\n  "basics_location": "Charlotte, NC",\n  "tell_us_more_what_brings_you": "Wanting new friends.",\n  "tell_us_more_friendship_meaning": "Friendship to me is a platonic relationship between two people that enjoy and feel comfortable around each other and are able to connect via interests, hobbies, and experience.",\n  "friendship_readiness_emotional_availability": "4",\n  "friendship_readiness_time_energy_capacity": "Moderate capacity (I can make time, but need flexibility)",\n  "friendship_readiness_friendship_intention": "I would like casual connections that could grow naturally over time",\n  "friendship_readiness_personal_work": "Yes, I''ve worked through a lot in therapy/self-reflection",\n  "friendship_readiness_life_circumstances": "N/A",\n  "friendship_readiness_life_circumstances_details": "",\n  "friendship_readiness_showing_up": "Having the ability to show up for a friend by either supporting them for an event or being present with them when they are going through tough times.",\n  "personality_social_style_recharge_style": "1",\n  "personality_social_style_social_settings": "Observe, listen deeply, and engage selectively",\n  "personality_social_style_ideal_hangout_0": "2",\n  "personality_social_style_ideal_hangout_1": "1",\n  "personality_social_style_ideal_hangout_2": "3",\n  "personality_social_style_ideal_hangout_3": "4",\n  "personality_social_style_making_plans": "I like having loose plans but staying flexible",\n  "personality_social_style_communication_preference": [\n    "Phone calls",\n    "Texting throughout the day"\n  ],\n  "personality_social_style_texting_style": "Thoughtful but slow to respond (hours to days)",\n  "conflict_repair_conflict_response": "Need time to process before I am ready to discuss",\n  "conflict_repair_repair_looks_like": [\n    "Written communication (text, letter, etc)",\n    "Time and space before reconnecting"\n  ],\n  "conflict_repair_flaky_friend_scenario": "Stay curious and check in:",\n  "conflict_repair_feedback_comfort": "3",\n  "conflict_repair_hurt_feelings_needs_0": "2",\n  "conflict_repair_hurt_feelings_needs_1": "4",\n  "conflict_repair_hurt_feelings_needs_2": "3",\n  "conflict_repair_hurt_feelings_needs_3": "5",\n  "conflict_repair_hurt_feelings_needs_4": "1",\n  "conflict_repair_boundary_setting": "I am clear and direct about my boundaries.",\n  "conflict_repair_friendship_lessons": "I tend to struggle with friendships that involve a trio since the other two friends want to hang out with each other without telling the group.",\n  "hobbies_interests_activities_interests": [\n    "Hosting gatherings (dinner parties, game nights)",\n    "Other"\n  ],\n  "hobbies_interests_activities_interests_other_text": "Video games",\n  "hobbies_interests_want_to_try": "Planning events since we are long distance friends.",\n  "hobbies_interests_free_time": "Playing video games, watching shows/anime",\n  "hobbies_interests_doing_vs_being": "Both",\n  "values_top_values_0": "6",\n  "values_top_values_1": "5",\n  "values_top_values_2": "7",\n  "values_top_values_3": "8",\n  "values_top_values_4": "9",\n  "values_top_values_5": "1",\n  "values_top_values_6": "3",\n  "values_top_values_7": "2",\n  "values_top_values_8": "10",\n  "values_top_values_9": "4",\n  "friendship_values_statements_resonate": [\n    "I appreciate friends who respect my need for space",\n    "Humor and laughter are essential to friendship",\n    "I value friends who share my worldview and values"\n  ],\n  "friendship_values_friendship_needs": [\n    "Emotional depth and vulnerability",\n    "Shared laughter and lightness",\n    "Intellectual stimulation",\n    "Non-judgment and acceptance",\n    "Consistency and reliability",\n    "Genuineness",\n    "Peaceful, easy presence"\n  ],\n  "friendship_values_non_negotiables