INSERT INTO "match" VALUES(1,7,10,1,2,'unmatched',NULL,replace('Hi {Madee},\n\nYou got matched! This is a test email to see blah blah blah. \n\nCheck out your Dashboard now: {https://www.threeofcupsllc.com}','\n',char(10)),'2025-11-21 19:41:46.831106','2025-11-21 20:01:00.863306',NULL,NULL);
INSERT INTO "match" VALUES(2,12,10,3,2,'unmatched',NULL,replace('Hi {first_name},\n\nGood news! You''ve been matched with a new friend on Three of Cups. \n\nAfter carefully reviewing both of your assessments, I have a really good feeling about this match.\nHere''s why I think you two will connect:\n\nYou both ranked shared laughter and personal growth in your top values, and you each expressed a desire for friendships where you can have light, but meaningful conversations. I noticed that {first_name}, you mentioned wanting a friend who "celebrates each other''s wins", and Iris, you described yourself as someone who "loves friends who check in consistently and help each other grow". That feels like beautiful alignment.\n\nYou also have complementary communication styles—{first_name}, you''re a dork who likes being insane, and Iris, you''re patient and amazing and super cool. I think you''ll navigate conflict together with a lot of grace.\n\nSome fun overlaps:\n\nYou both love being haters\nYou''re both exploring how unstable your family is\nYou both value being ADHD\n\nA gentle awareness: Robbie, you mentioned needing advance notice for plans, and Iris, you tend to be more spontaneous. This could actually be a beautiful balance if you both communicate openly about your needs!\n\nNext steps: I''ve sent this same message to both of you with each other''s contact info. I encourage you to reach out within the next few days to set up a casual first meeting—coffee, a walk, whatever feels right.\n\nContact info:\nIris - 1-800-chokethatho\n\nI''m rooting for you both! Remember, not every match will become a lifelong friendship, and that''s okay. Stay open, be yourselves, and see what unfolds.\n\nWith so much hope for beautiful connection, Iris 🌟','\n',char(10)),'2025-12-09 19:04:20.470419','2025-12-09 19:21:29.222552',NULL,NULL);
INSERT INTO "match" VALUES(18,7,8,1,20,'finalized',NULL,replace('Your Three of Cups Match: Meet {match_name}!\n\nHi {first_name},\n\nI''m so excited to introduce you to {match_name}! After carefully reviewing both of your assessments, I have a really good feeling about this match.\n\nHere''s why I think you two will connect:\n\nYou both ranked [values] in your top values, and you each expressed a desire for friendships where you can [friendship desire]. I noticed that {user1_name}, you mentioned wanting a friend who "[X]" and {user2_name}, you described yourself as someone who "[X]." That feels like a beautiful alignment.\n\nYou also have complementary [x such as communication styles]—{user1_name}, you''re a thoughtful processor who likes time before difficult conversations, and {user2_name}, you''re patient and prefer to understand someone''s perspective before responding. I think you''ll navigate conflict together with a lot of grace.\n\nSome fun overlaps:\n• You both love [shared hobby]\n• You''re both exploring [shared interest]\n• You both value [shared value]\n\nA gentle awareness: {user1_name}, you mentioned needing advance notice for plans, and {user2_name}, you tend to be more spontaneous. This could actually be a beautiful balance if you both communicate openly about your needs!\n\nNext steps: I''ve sent this same message to both of you with each other''s contact info. I encourage you to reach out within the next few days to set up a casual first meeting—coffee, a walk, whatever feels right.\n\nHere are a few ideas from the Three of Cups team:\n\nContact info:\n[Contact method and details]\n\nI''m rooting for you both! Remember, not every match will become a lifelong friendship, and that''s okay. Stay open, be yourselves, and see what unfolds.\n\nWith so much hope for beautiful connection,\nIris 🌟','\n',char(10)),'2026-01-01 23:45:18.288525','2026-01-09 21:01:40.874772','I love you -Shauna',replace('Your Three of Cups Match: Meet Madee!\n\nHi Shauna,\n\nI''m so excited to introduce you to Madee! After carefully reviewing both of your assessments, I have a really good feeling about this match.\n\nHere''s why I think you two will connect:\n\nYou both ranked humor in your top values, and you each expressed a desire for friendships where you can laugh. I noticed that Madee, you mentioned wanting a friend who has a sense of humor and Shauna, you described yourself as someone who doesn''t take life too serious. That feels like a beautiful alignment.\n\nYou also have complementary communication styles -- Madee, you''re a thoughtful processor who likes time before difficult conversations, and Shauna, you''re patient and prefer to understand someone''s perspective before responding. I think you''ll navigate conflict together with a lot of grace.\n\nSome fun overlaps:\n* You both love bonding over how dysfunctional your family is\n* You''re both exploring our family''s trauma\n* You both value peace and quiet\n\nA gentle awareness: Robbie, you mentioned needing advance notice for plans, and Iris, you tend to be more spontaneous. This could actually be a beautiful balance if you both communicate openly about your needs!\n\nNext steps: I''ve sent this same message to both of you with each other''s contact info. I encourage you to reach out within the next few days to set up a casual first meeting -- coffee, a walk, whatever feels right.\n\nHere are a few ideas from the Three of Cups team:\nBoba\nEating\nShit talking\n\nContact info:\nirishudson@icloud.com \n\nI''m rooting for you both! Remember, not every match will become a lifelong friendship, and that''s okay. Stay open, be yourselves, and see what unfolds.\n\nWith so much hope for beautiful connection,\nIris','\n',char(10)));
