INSERT INTO event VALUES(1,'friendship matchmaking launch party',replace('[MAX CAPACITY!!!!] \n\nhi friends! we are at max capacity for our matchmaking portion of the event. if you weren''t able to RSVP, please still free to come to the event and mingle with other folk looking for friendship. your assessments will still be utilized to match you with someone outside the event!','\n',char(10)),'Nguyen''s Noodles','2026-01-11 13:00:00.000000',NULL,NULL,'2025-12-08 16:37:10.532080',6,32,'t1PDmy9vTFTJ5_a3Io7W6LB_Iz74u5HXXm364LDpN78','2026-01-12 13:00:00.000000',NULL,NULL,NULL,0);
INSERT INTO event VALUES(2,'friendship matchmaking event',replace('join us for our second friendship matchmaking event of the year! come meet your match(es) at Nguyen''s Noodles &amp; Tea. we will have different stations where you can mix and mingle while making friendship bracelets, receive a tarot/oracle reading, get friendship advice, and/or buy some delicious boba, bahn mi, and so much more! \n\nbeen matched before? totally okay! we will match you again. just be sure to RSVP. \n\nsee you there!\n\nsuggested energy exchange (optional -- limited scholarships for those in need): $5.55 to $11.11\nvenmo: @threeofcupsllc','\n',char(10)),'Nguyen''s Noodles &amp; Tea','2026-03-28 15:33:00.000000',5.54999999999999982,'uploads/event_20260309172914_1.png','2026-03-09 17:29:14.489057',6,30,'Y3Q3F_Bo2ysDtgVscINxkL79v1KhQeUMcdsRtiA2ky4','2026-03-29 15:33:00.000000','3615 Whitehall Park Drive Suite I, Charlotte, NC 28273','2026-03-28 17:55:00.000000',11.1099999999999994,1);
INSERT INTO event VALUES(3,'friendship matchmaking event',replace('join us for our June friendship matchmaking event! come meet your match(es) at Sip City. we will have different stations where you can mix and mingle while making friendship bracelets, receive a tarot/oracle reading, get friendship advice, and/or buy some drinks, and so much more! \n\nbeen matched before? no worries --  we will match you again. be sure to RSVP! \n\nsee you there!\n\nsuggested energy exchange (optional -- limited scholarships for those in need): $5.55 to $15.55\nvenmo: @threeofcupsllc','\n',char(10)),'Sip City','2026-06-07 16:44:00.000000',7.76999999999999957,'uploads/event_20260517201224_Pink_and_Gold_Elegant_Brand_Event_Instagram_Post_Instagram_Post_45.jpg','2026-05-13 18:05:02.009361',6,32,NULL,NULL,'917 Central Avenue (Unit C), Charlotte, NC 28204','2026-06-07 18:30:00.000000',22.2199999999999988,1);
