INSERT INTO service VALUES(1,'basic reading via voice recording','$15',replace('A personalized tarot reading delivered through a voice recording! Whether it''s career, love, personal growth, or friendships, I''ll send you a voice recording where I mindfully draw cards and walk you through each card''s meaning and how they relate to your situation.\n\nDelivered within 3-5 business days!','\n',char(10)),0,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(2,'joint friendship reading via voice recording','$20',replace('Need a little bit more guidance in your friendship? This reading explores the current state of your friendship, underlying dynamics, and ways you both complement each other. I''ll send you both a voice recording where I draw cards and walk both of you through each card''s meaning and how they relate to your friendship.\n\nDelivered within 3-5 business days!','\n',char(10)),1,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(3,'basic friendship reading + 3 questions','$30',replace('This offering is for those who want to dive deeper into their social wellness. With this comprehensive reading, you will receive a voice recording that explores your overall friendship dynamic. After pulling cards and explaining each meaning as it relates to your friendship life, I''ll then answer three questions you submit ahead of time.\n\nDelivered within 3-5 business days!','\n',char(10)),2,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(4,'basic reading via voice recording + 3 questions','$25',replace('A personalized tarot reading on your chosen topic, plus the opportunity to ask three specific follow-up questions. This offering allows you to explore your situation broadly first, and then zoom in on particular aspects that matter most to you. Whether it''s career, love, personal growth, or life decisions, you''ll receive a comprehensive voice recording that addresses both the big picture and your specific concerns.\n\nDelivered within 3-5 business days!','\n',char(10)),3,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(5,'friendship guidance reading','$10',replace('This streamlined reading offers quick and meaningful insight into a friendship question or concern delivered through a voice recording. Ideal for check-ins, follow-up questions, or those wanting an introduction into tarot.\n\nDelivered within 3-5 business days!','\n',char(10)),4,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(6,'reading via zoom + 3 questions (45 minutes)','$40',replace('A live, interactive tarot reading from the comfort of your home! During our 45-minute Zoom session, we''ll explore your primary concern through a tarot spread, then address three questions of your choice. This format allows for real-time discussion, clarification, and deeper exploration of the cards'' messages. You''ll leave with insights and a clearer perspective.\n\nDelivered within 3-5 business days!','\n',char(10)),5,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(7,'joint friendship reading via zoom (1 hour)','$60 - 2 questions each',replace('A unique offering for friends who want to explore their friendship together. In this one-hour Zoom session, you, a pal, and I will read the cards to illuminate your friendship''s strengths, challenges, and growth opportunities. Each person will get a chance to ask two questions, creating space for mutual understanding and deeper connection. This collaborative experience can strengthen bonds and provide insights for navigating your friendship with greater awareness and care.\n\nDelivered within 3-5 business days!','\n',char(10)),6,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(8,'friendship coaching','(to be offered soon!)','Think couple''s counseling but for friendship. Stay tuned for more!',7,1,'2026-05-12 12:23:34');
INSERT INTO service VALUES(9,'life coaching','(to be offered soon!)','Coming soon!',8,1,'2026-05-12 12:23:34');
